  const calculateFees = () => {
      if (!foundBid) return;

      const supplyAmount = foundBid.amount;
      const parkingFee = 5000;
      const vatRate = 0.18; // URA Compliance
      const withholdingRate = 0.06; // URA Compliance for non-verified or bulk

      const vat = supplyAmount * vatRate;
      const total = parkingFee + vat;

      setPendingPayment({
          amount: total,
          taxAmount: vat,
