             <button onClick={() => setActiveTab('STOCK')} className={`px-6 py-3 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'STOCK' ? 'bg-white shadow-lg text-slate-900' : 'text-slate-500 hover:text-slate-800'}`}>Stock Verify</button>
          </div>
