import React, { useState } from 'react';
import { MOCK_TOKENS, MOCK_BIDS } from '../constants';
import { GateToken, VehicleCategory, Bid } from '../types';
import { PaymentGateway } from './PaymentGateway';
import { Card } from './ui/Card';
import { Button } from './ui/Button';
import { 
  QrCode, CheckCircle, Truck, Printer, Search, DollarSign, ShieldAlert,
  Calendar, ArrowRight, Smartphone, ShieldCheck, Download, X, Car, Bike, Info,
  LogOut, LogIn, Activity, History, Trash2, Camera
} from 'lucide-react';

const VEHICLE_FEES = {
  [VehicleCategory.HEAVY_TRUCK]: 15000,
  [VehicleCategory.LIGHT_VAN]: 7000,
  [VehicleCategory.SALOON_CAR]: 5000,
  [VehicleCategory.MOTORBIKE]: 2000
};

export const GateManagementModule: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'TERMINAL' | 'EXIT' | 'DELIVERIES' | 'LOGS'>('TERMINAL');
  const [tokens, setTokens] = useState<GateToken[]>(MOCK_TOKENS);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedVehicle, setSelectedVehicle] = useState<VehicleCategory>(VehicleCategory.SALOON_CAR);
  const [plateQuery, setPlateQuery] = useState('');

  // Accepted Bids (Upcoming Deliveries)
  const acceptedDeliveries = MOCK_BIDS.filter(b => b.status === 'ACCEPTED');

  // Flow State
  const [manifestCode, setManifestCode] = useState('');
  const [foundBid, setFoundBid] = useState<Bid | null>(null);
  const [pendingPayment, setPendingPayment] = useState<any | null>(null);
  const [receiptToken, setReceiptToken] = useState<GateToken | null>(null);

  const handleScanManifest = (codeOverride?: string) => {
      const code = codeOverride || manifestCode;
      if(!code) return;
      setIsLoading(true);

      setTimeout(() => {
          const match = acceptedDeliveries.find(d => code.includes(d.id.toUpperCase())) || acceptedDeliveries[0];
          setFoundBid(match);
          setIsLoading(false);
      }, 800);
  };

  const handleExitScan = (code: string) => {
      setIsLoading(true);
      setTimeout(() => {
          setTokens(prev => prev.map(t => t.code === code ? { ...t, status: 'USED' } : t));
          setIsLoading(false);
          alert(`Pass ${code} marked as EXITED. Gate open.`);
      }, 1000);
  };

  const calculateFees = () => {
      if (!foundBid) return;

      const parkingFee = VEHICLE_FEES[selectedVehicle];
      const vatRate = 0.18; // URA VAT Standard

      const vat = parkingFee * vatRate;
      const total = parkingFee + vat;

      setPendingPayment({
          amount: total,
          taxAmount: vat,
          description: `Gate Entry: ${foundBid.supplierName} (${selectedVehicle})`,
          parking: parkingFee
      });
  };

  const finalizeEntry = (txId: string) => {
      const newToken: GateToken = {
          id: `gt${Date.now()}`,
          code: `MMIS-ENT-${Math.floor(Math.random()*9000)+1000}`,
          type: 'ENTRY',
          entityName: foundBid?.supplierName || 'General Logistics',
          status: 'ACTIVE',
          generatedAt: new Date().toISOString(),
          vehicleType: selectedVehicle,
          associatedFee: pendingPayment.amount,
          taxAmount: pendingPayment.taxAmount
      };

      setTokens([newToken, ...tokens]);
      setReceiptToken(newToken);
      setPendingPayment(null);
      setFoundBid(null);
      setManifestCode('');
  };

  const VehicleIcon = ({ type }: { type: VehicleCategory }) => {
      switch(type) {
          case VehicleCategory.HEAVY_TRUCK: return <Truck size={20}/>;
          case VehicleCategory.MOTORBIKE: return <Bike size={20}/>;
          default: return <Car size={20}/>;
      }
  };

  return (
    <div className="space-y-6 animate-in fade-in pb-20">
       {pendingPayment && (
           <PaymentGateway 
              amount={pendingPayment.amount}
              taxAmount={pendingPayment.taxAmount}
              description={pendingPayment.description}
              onClose={() => setPendingPayment(null)}
              onSuccess={(txId) => finalizeEntry(txId)}
           />
       )}

       <div className="flex flex-col md:flex-row justify-between items-end gap-6 pb-6 border-b border-slate-200">
          <div className="flex items-center gap-5">
             <div className="w-16 h-16 bg-slate-900 text-white rounded-2xl flex items-center justify-center shadow-2xl ring-4 ring-slate-100">
                <Smartphone size={32} />
             </div>
             <div>
                <h2 className="text-3xl font-black text-slate-900 tracking-tighter uppercase">Gate Operations</h2>
                <p className="text-slate-500 font-medium">Registry triangulation & URA tax audit node.</p>
             </div>
          </div>
          <div className="flex bg-slate-100 p-1.5 rounded-2xl shadow-inner border border-slate-200">
             <button onClick={() => setActiveTab('TERMINAL')} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'TERMINAL' ? 'bg-white shadow-lg text-indigo-600' : 'text-slate-500 hover:text-slate-800'}`}>
                <LogIn size={14}/> Inbound
             </button>
             <button onClick={() => setActiveTab('EXIT')} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'EXIT' ? 'bg-white shadow-lg text-red-600' : 'text-slate-500 hover:text-slate-800'}`}>
                <LogOut size={14}/> Outbound
             </button>
             <button onClick={() => setActiveTab('DELIVERIES')} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'DELIVERIES' ? 'bg-white shadow-lg text-slate-900' : 'text-slate-500 hover:text-slate-800'}`}>
                <History size={14}/> Manifests
             </button>
             <button onClick={() => setActiveTab('LOGS')} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2 ${activeTab === 'LOGS' ? 'bg-white shadow-lg text-slate-900' : 'text-slate-500 hover:text-slate-800'}`}>
                <Activity size={14}/> System Log
             </button>
          </div>
       </div>

       {activeTab === 'TERMINAL' && (
         <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
             <div className="lg:col-span-2 space-y-6">
                <Card className="p-10 rounded-[48px] border-none shadow-2xl bg-white relative overflow-hidden ring-1 ring-slate-100">
                    <div className="relative z-10">
                        <h3 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-4 tracking-tight uppercase">
                           <div className="p-4 bg-slate-900 text-white rounded-2xl shadow-xl"><QrCode size={28}/></div>
                           Triangulate Manifest
                        </h3>

                        <div className="space-y-8 mb-10">
                            <div>
                                <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1 mb-4 block">1. Classify Vehicle Node</label>
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                    {Object.entries(VEHICLE_FEES).map(([type, fee]) => (
                                        <button 
                                            key={type}
                                            onClick={() => setSelectedVehicle(type as VehicleCategory)}
                                            className={`p-5 rounded-3xl border-2 transition-all flex flex-col items-center gap-2 ${selectedVehicle === type ? 'border-indigo-600 bg-indigo-50 text-indigo-900' : 'border-slate-50 text-slate-500 hover:bg-slate-50 hover:border-slate-200'}`}
                                        >
                                            <div className={`p-3 rounded-2xl ${selectedVehicle === type ? 'bg-indigo-600 text-white' : 'bg-slate-100'}`}>
                                                <VehicleIcon type={type as VehicleCategory} />
                                            </div>
                                            <span className="text-[10px] font-black uppercase tracking-tighter mt-1">{type.replace('_', ' ')}</span>
                                            <span className="text-[11px] font-bold opacity-60">{fee.toLocaleString()} UGX</span>
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest ml-1 mb-4 block">2. Verify Logistics ID / Plate</label>
                                <div className="flex gap-4">
                                    <div className="relative flex-1">
                                        <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={24} />
                                        <input 
                                            type="text" 
                                            className="w-full pl-14 pr-6 py-6 rounded-3xl border-2 border-slate-100 bg-slate-50 font-mono text-xl tracking-[0.2em] focus:bg-white focus:border-indigo-600 outline-none transition-all uppercase placeholder:text-slate-200 shadow-inner" 
                                            placeholder="TOKEN-OR-PLATE"
                                            value={manifestCode}
                                            onChange={e => setManifestCode(e.target.value.toUpperCase())}
                                        />
                                    </div>
                                    <Button onClick={() => handleScanManifest()} loading={isLoading} className="h-full px-12 rounded-3xl uppercase font-black tracking-[0.2em] text-xs shadow-2xl shadow-indigo-100">Verify</Button>
                                </div>
                            </div>
                        </div>

                        {foundBid && (
                            <div className="animate-in slide-in-from-bottom-6 space-y-8 p-8 rounded-[40px] border-2 border-emerald-100 bg-emerald-50/20">
                                <div className="flex justify-between items-start">
                                    <div>
                                        <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1 flex items-center gap-2"><ShieldCheck size={16}/> Identity Validated</p>
                                        <p className="text-3xl font-black text-slate-900 leading-tight">{foundBid.supplierName}</p>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Magnitude</p>
                                        <p className="text-3xl font-black text-indigo-600 tracking-tighter">{foundBid.amount.toLocaleString()} UGX</p>
                                    </div>
                                </div>

                                <div className="bg-white border border-slate-200 p-6 rounded-[32px] flex gap-6 items-center shadow-sm">
                                    <div className="w-14 h-14 bg-amber-50 text-amber-500 rounded-2xl flex items-center justify-center shrink-0">
                                        <ShieldAlert size={32} />
                                    </div>
                                    <div>
                                        <p className="text-xs font-black text-slate-900 uppercase tracking-widest mb-1">Fiscal Responsibility</p>
                                        <p className="text-xs font-medium text-slate-500 leading-relaxed">
                                            Registry protocols apply 18% URA VAT to {selectedVehicle.replace('_', ' ')} entrance fees. Parking node allocation included.
                                        </p>
                                    </div>
                                </div>

                                <Button onClick={calculateFees} className="w-full h-24 rounded-[32px] font-black uppercase tracking-[0.2em] text-sm shadow-[0_20px_40px_rgba(79,70,229,0.3)] bg-indigo-600 border-none">
                                    Authorize Entry & Process Settlement
                                </Button>
                            </div>
                        )}
                    </div>
                </Card>
             </div>

             <div className="space-y-6">
                <Card className="p-8 rounded-[48px] border-none shadow-xl bg-slate-900 text-white relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-8 opacity-10"><Activity size={100}/></div>
                    <h4 className="font-black uppercase tracking-[0.2em] text-[10px] text-indigo-400 mb-8 relative z-10">Real-time Pass Ledger</h4>
                    <div className="space-y-6 relative z-10">
                        {tokens.slice(0, 4).map(t => (
                            <div key={t.id} className="flex items-center justify-between p-5 rounded-[28px] bg-white/5 border border-white/10 shadow-inner group hover:bg-white/10 transition-all cursor-pointer">
                                <div className="flex items-center gap-4">
                                    <div className={`p-3 rounded-2xl transition-colors ${t.status === 'ACTIVE' ? 'bg-emerald-500/20 text-emerald-400' : 'bg-slate-500/20 text-slate-400'}`}>
                                        <Truck size={24} />
                                    </div>
                                    <div>
                                        <p className="text-sm font-black tracking-tight uppercase">{t.entityName}</p>
                                        <p className="text-[10px] text-slate-500 font-mono tracking-widest mt-0.5">{t.code}</p>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <span className={`px-2 py-0.5 rounded-full text-[8px] font-black uppercase ${t.status === 'ACTIVE' ? 'bg-emerald-500 text-white' : 'bg-slate-700 text-slate-400'}`}>{t.status}</span>
                                </div>
                            </div>
                        ))}
                    </div>
                    <Button variant="ghost" className="w-full mt-6 text-slate-500 hover:text-white text-[10px] font-black uppercase tracking-widest">Load Full Register &rarr;</Button>
                </Card>

                <div className="bg-white p-10 rounded-[48px] border border-slate-100 shadow-xl text-center group hover:border-red-100 transition-all">
                   <div className="w-16 h-16 bg-red-50 text-red-500 rounded-2xl flex items-center justify-center mx-auto mb-6 group-hover:scale-110 transition-transform">
                      <LogOut size={32} />
                   </div>
                   <h5 className="font-black uppercase text-[10px] tracking-[0.2em] text-slate-400 mb-2">Outbound Triage</h5>
                   <p className="text-xs text-slate-400 mb-6 font-medium">Verify exit authorization code.</p>
                   <input 
                      className="w-full px-6 py-5 rounded-2xl bg-slate-50 border-2 border-slate-100 outline-none mb-4 text-center font-mono font-black text-lg focus:border-red-500 transition-all shadow-inner" 
                      placeholder="ENTER PASS CODE" 
                   />
                   <Button variant="secondary" className="w-full h-14 uppercase font-black text-[10px] tracking-[0.2em] border-2 rounded-2xl hover:bg-red-50 hover:text-red-600 hover:border-red-100">Synchronize Departure</Button>
                </div>
             </div>
         </div>
       )}

       {activeTab === 'EXIT' && (
         <div className="max-w-4xl mx-auto py-12 animate-in fade-in slide-in-from-bottom-10">
            <Card className="rounded-[64px] shadow-2xl border-none p-16 text-center bg-slate-900 text-white relative overflow-hidden">
               <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>
               <div className="relative z-10">
                  <div className="w-24 h-24 bg-red-500/20 text-red-500 rounded-[32px] flex items-center justify-center mx-auto mb-10 border border-red-500/30">
                     <Camera size={48} className="animate-pulse" />
                  </div>
                  <h3 className="text-4xl font-black tracking-tighter mb-4 uppercase">Departure Node Scan</h3>
                  <p className="text-slate-400 text-lg font-medium leading-relaxed mb-12 max-w-md mx-auto">Triage active tokens for outbound logistics. Registry will automatically verify time-delta and parking surcharges.</p>

                  <div className="flex gap-4 max-w-md mx-auto mb-8">
                     <input 
                        type="text" 
                        placeholder="TOKEN-ID-8821" 
                        className="flex-1 bg-white/5 border-2 border-white/10 rounded-2xl px-6 py-5 font-mono font-black text-xl tracking-[0.3em] outline-none focus:border-red-500 transition-all text-center uppercase"
                        onChange={(e) => setPlateQuery(e.target.value.toUpperCase())}
                     />
                     <Button 
                        onClick={() => handleExitScan(plateQuery)}
                        className="bg-red-600 hover:bg-red-700 text-white px-10 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-2xl shadow-red-900/40"
                     >
                        Finalize
                     </Button>
                  </div>

                  <div className="flex items-center justify-center gap-6 text-slate-500">
                     <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest"><CheckCircle size={14} className="text-emerald-500"/> OCR Active</div>
                     <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest"><CheckCircle size={14} className="text-emerald-500"/> AI Plate Recognition</div>
                  </div>
               </div>
            </Card>
         </div>
       )}

       {activeTab === 'DELIVERIES' && (
           <div className="animate-in fade-in grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
               {acceptedDeliveries.map(bid => (
                   <Card key={bid.id} className="p-10 rounded-[48px] border-none shadow-xl bg-white group hover:shadow-2xl transition-all relative overflow-hidden">
                       <div className="absolute top-0 right-0 p-10 opacity-5 group-hover:opacity-10 transition-opacity"><Truck size={150}/></div>
                       <div className="flex justify-between items-start mb-8 relative z-10">
                           <div className="p-5 bg-indigo-50 text-indigo-600 rounded-3xl group-hover:bg-indigo-600 group-hover:text-white transition-colors shadow-lg">
                               <Truck size={32} />
                           </div>
                           <span className="text-[10px] font-black bg-emerald-100 text-emerald-700 px-4 py-1.5 rounded-full uppercase tracking-widest border border-emerald-200">ACCEPTED</span>
                       </div>
                       <h4 className="text-2xl font-black text-slate-900 mb-2 leading-tight uppercase tracking-tight relative z-10">{bid.supplierName}</h4>
                       <p className="text-sm font-bold text-slate-400 mb-10 flex items-center gap-2 uppercase tracking-widest relative z-10">
