                               <p className="text-xl font-black text-slate-900">{bid.amount.toLocaleString()} <span className="text-xs font-bold opacity-30">UGX</span></p>
                           </div>
                           <div className="w-12 h-12 bg-white rounded-2xl shadow-xl flex items-center justify-center group-hover:translate-x-1 transition-transform">
                               <ArrowRight size={24} className="text-indigo-600" />
                           </div>
                       </div>
                       <Button 
                            onClick={() => {
                                setManifestCode(`MMIS-MAN-${bid.id.toUpperCase()}`);
                                setActiveTab('TERMINAL');
                                handleScanManifest(`MMIS-MAN-${bid.id.toUpperCase()}`);
                            }}
                            className="w-full h-16 rounded-3xl font-black uppercase text-[11px] tracking-[0.3em] shadow-xl relative z-10"
