       <input type={type} placeholder={placeholder} className="w-full px-4 py-3 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-indigo-500 font-bold text-sm transition-all placeholder:text-slate-300 shadow-inner" />
