import React, { useState, useMemo } from 'react';
import { UserRole, Transaction, PaymentType } from '../types';
import { MOCK_TRANSACTIONS } from '../constants';
import { 
  DollarSign, Download, CreditCard, Wallet, ArrowUpRight, ArrowDownLeft, 
  PieChart, TrendingUp, Lock, Filter, Calendar, Check, AlertTriangle,
  Building2, Truck, Gavel, Zap, FileText, X, ChevronRight, Search, ArrowUpDown,
  History, Activity, ShieldCheck
} from 'lucide-react';
import { Button } from './ui/Button';
import { Card } from './ui/Card';

interface FinancialsModuleProps {
  role: UserRole;
  marketId?: string;
}

export const FinancialsModule: React.FC<FinancialsModuleProps> = ({ role, marketId }) => {
  const isAdmin = role === UserRole.SUPER_ADMIN || role === UserRole.MARKET_ADMIN;
  const isVendor = role === UserRole.VENDOR;
  const isSupplier = role === UserRole.SUPPLIER;

  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState<PaymentType | 'ALL'>('ALL');
  const [statusFilter, setStatusFilter] = useState<'ALL' | 'PAID' | 'PENDING' | 'OVERDUE'>('ALL');
  const [sortField, setSortField] = useState<'date' | 'amount'>('date');
  const [sortDir, setSortDir] = useState<'ASC' | 'DESC'>('DESC');

  const filteredTransactions = useMemo(() => {
    return MOCK_TRANSACTIONS.filter(tx => {
      // 1. RBAC Isolation
      if (isVendor) {
        if (![PaymentType.RENT, PaymentType.URA_VAT, PaymentType.UTILITY].includes(tx.type)) return false;
      } else if (isSupplier) {
        if (![PaymentType.SUPPLY_ESCROW, PaymentType.SERVICE_CHARGE].includes(tx.type)) return false;
      }

      // 2. Local Node Filters
      if (filterType !== 'ALL' && tx.type !== filterType) return false;
      if (statusFilter !== 'ALL' && tx.status !== statusFilter) return false;

      const term = searchTerm.toLowerCase();
      const matchesSearch = !term || 
          (tx.reference && tx.reference.toLowerCase().includes(term)) ||
          tx.id.toLowerCase().includes(term) ||
          tx.method.toLowerCase().includes(term);

      return matchesSearch;
    }).sort((a, b) => {
      let valA = a[sortField];
      let valB = b[sortField];
      if (typeof valA === 'string') {
          return sortDir === 'ASC' ? valA.localeCompare(valB as string) : (valB as string).localeCompare(valA);
      }
      return sortDir === 'ASC' ? (valA as number) - (valB as number) : (valB as number) - (valA as number);
    });
  }, [searchTerm, filterType, statusFilter, sortField, sortDir, isVendor, isSupplier]);

  const stats = useMemo(() => {
    const paid = filteredTransactions.filter(t => t.status === 'PAID');
    const total = paid.reduce((acc, curr) => acc + curr.amount, 0);
    const tax = paid.reduce((acc, curr) => acc + (curr.taxAmount || 0), 0);
    const pending = filteredTransactions.filter(t => t.status === 'PENDING').reduce((acc, curr) => acc + curr.amount, 0);
    return { total, tax, pending };
  }, [filteredTransactions]);

  const toggleSort = (field: 'date' | 'amount') => {
    if (sortField === field) setSortDir(prev => prev === 'ASC' ? 'DESC' : 'ASC');
    else { setSortField(field); setSortDir('DESC'); }
  };

  return (
    <div className="space-y-8 animate-in fade-in pb-20">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pb-6 border-b border-slate-200">
        <div className="flex items-center gap-5">
           <div className="w-16 h-16 bg-slate-900 text-white rounded-2xl flex items-center justify-center shadow-2xl ring-4 ring-slate-100">
             <Wallet size={32} />
           </div>
           <div>
              <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Revenue Hub</h2>
              <p className="text-slate-500 font-medium text-lg">Classified fiscal triangulation and settlement node.</p>
           </div>
        </div>
        <div className="flex gap-3">
           <Button variant="outline" className="h-12 border-2 px-6"><Download size={18} className="mr-2"/> Export Ledger</Button>
           {isAdmin && (
             <Button className="h-12 px-8 font-black uppercase tracking-widest text-xs shadow-xl shadow-indigo-100">
                <Activity size={18} className="mr-2"/> Audit remissions
             </Button>
           )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 bg-slate-900 rounded-[48px] p-12 text-white relative overflow-hidden shadow-[0_30px_60px_-15px_rgba(0,0,0,0.3)]">
            <div className="relative z-10">
                <p className="text-indigo-400 font-black uppercase tracking-[0.3em] text-[10px] mb-4">Liquidized Revenue (MTD)</p>
                <div className="flex items-baseline gap-4 mb-10">
                    <h3 className="text-7xl font-black tracking-tighter">{stats.total.toLocaleString()}</h3>
                    <span className="text-2xl font-medium opacity-30">UGX</span>
                </div>
                <div className="grid grid-cols-3 gap-12 border-t border-white/10 pt-10">
                    <div>
                        <p className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Net Node Value</p>
                        <p className="text-2xl font-black text-emerald-400">{(stats.total - stats.tax).toLocaleString()}</p>
                    </div>
                    <div>
                        <p className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Tax Remission</p>
                        <p className="text-2xl font-black text-orange-400">{stats.tax.toLocaleString()}</p>
                    </div>
                    <div>
                        <p className="text-[9px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Remission Rate</p>
                        <p className="text-2xl font-black text-indigo-400">98.4%</p>
                    </div>
                </div>
            </div>
            <DollarSign className="absolute -right-20 -bottom-20 text-white opacity-5" size={450} />
        </div>

        <div className="flex flex-col gap-6">
            <Card className="flex-1 bg-white rounded-[40px] p-8 border border-slate-200 shadow-sm flex flex-col justify-between group hover:border-red-200 transition-all">
                <div>
                    <div className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-4">Pending Obligations</div>
                    <p className="text-4xl font-black text-red-600 mb-2">{stats.pending.toLocaleString()}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest leading-relaxed">Arrears detected in regional sector registry.</p>
                </div>
                <button className="w-full py-4 bg-red-50 text-red-700 font-black uppercase text-[10px] tracking-[0.2em] rounded-2xl hover:bg-red-100 transition shadow-sm">
                    Settle Dues
                </button>
            </Card>
            <div className="bg-indigo-600 rounded-[40px] p-8 text-white shadow-xl flex items-center justify-between overflow-hidden relative">
                <div className="relative z-10">
                    <p className="text-[9px] font-black uppercase tracking-[0.2em] opacity-60 mb-1">Compliance</p>
                    <p className="text-3xl font-black">94.2%</p>
                </div>
                <div className="w-14 h-14 bg-white/10 rounded-2xl flex items-center justify-center relative z-10">
                    <ShieldCheck size={28} className="text-white"/>
                </div>
                <Zap className="absolute -right-4 -bottom-4 text-white opacity-10" size={100}/>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-[48px] border border-slate-200 shadow-xl overflow-hidden">
          <div className="p-8 border-b border-slate-100 bg-slate-50/50 space-y-6">
              <div className="flex flex-col md:flex-row justify-between items-center gap-6">
                  <h3 className="font-black text-slate-900 uppercase tracking-tight text-xl flex items-center gap-4">
                      <History className="text-indigo-600" size={24} /> Transaction Matrix
                  </h3>
                  <div className="flex flex-wrap gap-3">
                       <div className="relative">
                           <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16}/>
                           <input 
                              type="text" 
                              placeholder="Search reference..." 
                              className="pl-12 pr-4 py-3 bg-white border-2 border-slate-100 rounded-2xl text-[10px] font-black uppercase outline-none focus:border-indigo-600 transition-all w-60 shadow-inner"
                              value={searchTerm}
                              onChange={e => setSearchTerm(e.target.value)}
                           />
                       </div>
                       <select 
                          className="bg-white border-2 border-slate-100 rounded-2xl px-6 py-3 text-[10px] font-black uppercase tracking-widest outline-none focus:border-indigo-600 cursor-pointer shadow-sm"
                          value={statusFilter}
                          onChange={(e) => setStatusFilter(e.target.value as any)}
                       >
                          <option value="ALL">All Statuses</option>
                          <option value="PAID">Liquidized</option>
                          <option value="PENDING">Pending</option>
                          <option value="OVERDUE">Overdue</option>
                       </select>
                       <select 
                          className="bg-slate-900 text-white border-none rounded-2xl px-6 py-3 text-[10px] font-black uppercase tracking-widest outline-none shadow-2xl cursor-pointer"
                          value={filterType}
                          onChange={(e) => setFilterType(e.target.value as any)}
                       >
                          <option value="ALL">All Classifications</option>
                          {Object.values(PaymentType).map(type => (
                              <option key={type} value={type}>{type.replace('_', ' ')}</option>
                          ))}
                       </select>
                  </div>
              </div>
          </div>
          <div className="overflow-x-auto">
              <table className="w-full text-sm text-left">
                  <thead className="bg-white text-slate-400 font-black uppercase text-[10px] tracking-[0.3em] border-b border-slate-100">
                      <tr>
                          <th className="px-10 py-8">Reference ID</th>
