                          </th>
                          <th className="px-10 py-8 cursor-pointer hover:text-indigo-600 transition-colors text-right" onClick={() => toggleSort('amount')}>
                              Magnitude {sortField === 'amount' && (sortDir === 'ASC' ? '↑' : '↓')}
                          </th>
                          <th className="px-10 py-8 text-center">Status Protocol</th>
                          <th className="px-10 py-8 text-right">Method</th>
                      </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                      {filteredTransactions.map(tx => (
                          <tr key={tx.id} className="hover:bg-indigo-50/30 transition-colors group">
