  const getRentStatus = (vendor: Vendor) => {
    if (vendor.rentDue <= 0) return { label: 'PAID', color: 'bg-emerald-500', text: 'text-emerald-700', bg: 'bg-emerald-100' };
    const dueDate = vendor.rentDueDate ? new Date(vendor.rentDueDate) : null;
    const today = new Date();
    if (dueDate && dueDate < today) return { label: 'OVERDUE', color: 'bg-red-500', text: 'text-red-700', bg: 'bg-red-100' };
    return { label: 'PENDING', color: 'bg-amber-500', text: 'text-amber-700', bg: 'bg-amber-100' };
  };

  const filteredAndSortedVendors = useMemo(() => {
    return vendors.filter(v => {
      const term = searchTerm.toLowerCase();
      const matchesSearch = v.name.toLowerCase().includes(term) || v.shopNumber.toLowerCase().includes(term);
      const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;
      const matchesMarket = selectedMarket === 'ALL' || v.marketId === selectedMarket;
      return matchesSearch && matchesStatus && matchesMarket;
    }).sort((a, b) => {
      const comparison = a.name.localeCompare(b.name);
      return nameSortOrder === 'ASC' ? comparison : -comparison;
    });
  }, [vendors, searchTerm, statusFilter, selectedMarket, nameSortOrder]);

  const toggleSelect = (id: string) => {
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === filteredAndSortedVendors.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredAndSortedVendors.map(v => v.id)));
    }
  };

  const handleBulkAction = (action: 'ACTIVATE' | 'SUSPEND') => {
    if (selectedIds.size === 0) return;
    const nextStatus = action === 'ACTIVATE' ? 'ACTIVE' : 'SUSPENDED';
    setVendors(prev => prev.map(v => 
      selectedIds.has(v.id) ? { ...v, status: nextStatus as any } : v
    ));
    setSelectedIds(new Set());
    alert(`Bulk operation: ${action} applied to ${selectedIds.size} nodes.`);
  };

  return (
    <div className="space-y-6 animate-in fade-in pb-20">
      {/* Header & Meta */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pb-6 border-b border-slate-200">
        <div className="flex items-center gap-5">
           <div className="w-16 h-16 bg-slate-900 text-white rounded-2xl flex items-center justify-center shadow-2xl ring-4 ring-slate-100">
             <Store size={32} />
           </div>
           <div>
              <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Vendor Registry</h2>
              <p className="text-slate-500 font-medium text-lg">Identity management and financial triangulation node.</p>
           </div>
        </div>

        {isAdmin && selectedIds.size > 0 && (
          <div className="flex gap-2 animate-in slide-in-from-right-4">
             <Button onClick={() => handleBulkAction('ACTIVATE')} className="bg-emerald-600 hover:bg-emerald-700 h-12 px-6 font-black uppercase text-[10px] tracking-widest shadow-xl">
                <Play size={14} className="mr-2"/> Activate Selected
             </Button>
             <Button onClick={() => handleBulkAction('SUSPEND')} className="bg-red-600 hover:bg-red-700 h-12 px-6 font-black uppercase text-[10px] tracking-widest shadow-xl">
                <Ban size={14} className="mr-2"/> Suspend Selected
             </Button>
          </div>
        )}
      </div>

      {/* Control Bar */}
      <div className="bg-white p-6 rounded-[32px] border border-slate-200 shadow-sm flex flex-wrap gap-4 items-center justify-between">
        <div className="flex flex-wrap gap-4 flex-1">
          <div className="relative flex-1 min-w-[300px]">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Triangulate vendor name or shop node..." 
              className="w-full pl-12 pr-4 py-3.5 border-2 border-slate-100 rounded-2xl text-sm font-bold bg-slate-50 focus:bg-white focus:border-indigo-600 outline-none transition-all shadow-inner"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <select className="px-4 py-3 border-2 border-slate-100 rounded-2xl text-[10px] font-black uppercase tracking-widest bg-slate-50 outline-none focus:border-indigo-600 appearance-none min-w-[160px]" value={selectedMarket} onChange={(e) => setSelectedMarket(e.target.value)}>
              <option value="ALL">All Markets</option>
              {MARKETS.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
          </select>

          <button 
            onClick={() => setNameSortOrder(prev => prev === 'ASC' ? 'DESC' : 'ASC')}
            className="px-6 py-3 border-2 border-slate-100 rounded-2xl text-[10px] font-black uppercase tracking-widest bg-slate-50 flex items-center gap-2 hover:bg-slate-100 transition-all"
          >
            Alphabetical {nameSortOrder === 'ASC' ? <ArrowUp size={14}/> : <ArrowDown size={14}/>}
          </button>
        </div>
      </div>

      {/* Table Node */}
      <div className="bg-white rounded-[48px] border border-slate-200 shadow-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50/50 text-slate-400 font-black uppercase text-[10px] tracking-[0.2em] border-b border-slate-100">
              <tr>
                {isAdmin && (
                  <th className="px-8 py-6 w-10">
                    <button onClick={toggleSelectAll} className="text-slate-400 hover:text-indigo-600 transition-colors">
                      {selectedIds.size === filteredAndSortedVendors.length ? <CheckSquare size={20}/> : <Square size={20}/>}
                    </button>
                  </th>
                )}
                <th className="px-8 py-6">Operator Node</th>
                <th className="px-8 py-6">Shop Unit</th>
                <th className="px-8 py-6">Fiscal Status</th>
                <th className="px-8 py-6">Access Status</th>
                <th className="px-8 py-6 text-right">Details</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredAndSortedVendors.map(vendor => {
                const rent = getRentStatus(vendor);
                return (
                  <tr key={vendor.id} className={`hover:bg-indigo-50/30 transition-colors group cursor-pointer ${selectedIds.has(vendor.id) ? 'bg-indigo-50' : ''}`} onClick={() => setSelectedVendor(vendor)}>
                    {isAdmin && (
                      <td className="px-8 py-6" onClick={(e) => { e.stopPropagation(); toggleSelect(vendor.id); }}>
                        <button className={`transition-colors ${selectedIds.has(vendor.id) ? 'text-indigo-600' : 'text-slate-300'}`}>
                           {selectedIds.has(vendor.id) ? <CheckSquare size={20}/> : <Square size={20}/>}
                        </button>
                      </td>
                    )}
                    <td className="px-8 py-6">
                      <div className="font-black text-slate-900 group-hover:text-indigo-600 transition-colors uppercase tracking-tight">{vendor.name}</div>
                      <div className="text-[10px] text-slate-400 font-bold mt-0.5 tracking-widest">{vendor.email}</div>
                    </td>
                    <td className="px-8 py-6">
                        <div className="font-mono text-xs font-black text-slate-700">{vendor.shopNumber}</div>
                        <div className="text-[9px] text-slate-400 uppercase font-black tracking-widest mt-0.5">{vendor.section || 'General Sector'}</div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-3">
                         <div className={`w-3 h-3 rounded-full ${rent.color} shadow-sm border border-white`}></div>
                         <div className={`px-2.5 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest border ${rent.text} ${rent.bg}`}>
                            {rent.label}
                         </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${vendor.status === 'ACTIVE' ? 'bg-indigo-50 text-indigo-600 border-indigo-100' : 'bg-red-50 text-red-600 border-red-100'}`}>
                        {vendor.status}
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <div className="flex justify-end gap-2">
                         <button onClick={(e) => { e.stopPropagation(); setQrModalVendor(vendor); }} className="p-3 bg-slate-50 hover:bg-slate-900 hover:text-white rounded-2xl transition-all shadow-sm">
                           <QrCode size={18} />
                         </button>
                         <button className="p-3 bg-slate-50 hover:bg-indigo-600 hover:text-white rounded-2xl transition-all shadow-sm">
                           <ArrowUpDown size={18} className="rotate-90" />
                         </button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* QR Store Passport Modal */}
      {qrModalVendor && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4 animate-in fade-in">
          <div className="bg-white rounded-[64px] shadow-2xl max-w-sm w-full p-12 text-center relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-3 bg-indigo-600"></div>
            <button onClick={() => setQrModalVendor(null)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-900 transition-colors"><X size={32}/></button>

            <div className="mb-10">
              <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-6 shadow-xl ring-4 ring-white">
                <Store size={48} />
              </div>
              <h3 className="text-3xl font-black text-slate-900 tracking-tighter uppercase leading-none mb-2">Store Passport</h3>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Digital Registry Node</p>
            </div>

            <div className="bg-slate-900 p-8 rounded-[48px] shadow-2xl mb-10 border-4 border-slate-800">
               <div className="bg-white p-6 rounded-3xl shadow-inner flex items-center justify-center">
                  <QrCode size={180} className="text-slate-900" />
               </div>
               <p className="text-white mt-8 font-mono text-xs font-black tracking-[0.4em] uppercase opacity-60">
                  {qrModalVendor.id}-{qrModalVendor.shopNumber}
               </p>
            </div>

            <div className="flex gap-4">
               <Button variant="secondary" className="flex-1 h-14 rounded-2xl font-black uppercase text-[10px] tracking-widest"><Printer size={18}/> Label</Button>
               <Button className="flex-1 h-14 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-indigo-100"><Download size={18}/> Export</Button>
            </div>
          </div>
        </div>
      )}

      {selectedVendor && (
        <VendorDetailsModal 
          vendor={selectedVendor} 
          userRole={userRole} 
          onClose={() => setSelectedVendor(null)} 
          onUpdateVendor={(u) => setVendors(prev => prev.map(v => v.id === u.id ? u : v))} 
        />
      )}
    </div>
  );
};

/* Using custom styled checkbox components, removing duplicates from lucide-react imports and importing 'Check' icon instead */
const CheckSquare = ({ size }: { size: number }) => (
  <div className="bg-indigo-600 text-white rounded-md p-0.5"><Check size={size-4} strokeWidth={4}/></div>
);

const Square = ({ size }: { size: number }) => (
  <div className="border-2 border-slate-300 rounded-md w-5 h-5"></div>
);

import React, { useState, useMemo } from 'react';
