                            <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Established</p>
                            <p className="text-sm font-black text-slate-800">{new Date(market.establishmentDate).getFullYear()}</p>
                        </div>
                    </div>
                </div>
            ))}
        </div>
      )}

      {viewMode === 'MAP' && <InteractiveMap markets={filteredMarkets} onMarketSelect={setSelectedMarket} />}

      {viewMode === 'ANALYTICS' && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <Card className="p-10 rounded-[48px] border-none shadow-xl flex flex-col items-center justify-between min-h-[500px]">
                <div className="text-center mb-8">
                    <h4 className="font-black uppercase text-sm tracking-widest text-slate-900 mb-2">Hub Capacity vs Establishment</h4>
                    <p className="text-xs font-medium text-slate-500">Visualizing node magnitude relative to infrastructure age.</p>
