                                          >
                                              <CheckCircle2 size={14} /> Accept Offer
                                          </button>
                                      </div>
                                  )}
                              </div>
                          ))
                      )}
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Vendor, UserRole, ProductCategory } from '../types';
import { MOCK_VENDORS, MARKETS } from '../constants';
import { 
  Search, QrCode, UserPlus, Store, ArrowUpDown, 
  ShieldCheck, Play, Ban, X, Download, Printer, Filter, 
  CheckSquare, Square, DollarSign, ListFilter, MoreVertical,
  Building2, MapPin, User, ChevronDown
} from 'lucide-react';
import { Button } from './ui/Button';
import { VendorDetailsModal } from './VendorDetailsModal';

interface VendorModuleProps {
  userRole?: UserRole;
  currentUserId?: string;
  marketId?: string;
}

export const VendorModule: React.FC<VendorModuleProps> = ({ 
  userRole = UserRole.USER, 
  currentUserId, 
  marketId 
}) => {
  const [vendors, setVendors] = useState<Vendor[]>(MOCK_VENDORS);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [searchTerm, setSearchTerm] = useState('');

  // RBAC Lock: Market Admins cannot change their market hub
  const initialMarket = (userRole === UserRole.MARKET_ADMIN || userRole === UserRole.GATE_STAFF) ? marketId : 'ALL';
  const [selectedMarket, setSelectedMarket] = useState(initialMarket || 'ALL');

  const [statusFilter, setStatusFilter] = useState('ALL');
  const [rentSortOrder, setRentSortOrder] = useState<'LOW_HIGH' | 'HIGH_LOW' | 'NONE'>('NONE');
  const [nameSortOrder, setNameSortOrder] = useState<'A_Z' | 'Z_A' | 'NONE'>('NONE');
  const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(null);
  const [qrModalVendor, setQrModalVendor] = useState<Vendor | null>(null);

  const isSuperAdmin = userRole === UserRole.SUPER_ADMIN;
  const isMarketAdmin = userRole === UserRole.MARKET_ADMIN;
  const isAdmin = isSuperAdmin || isMarketAdmin;

  // Enforce market lock if it changes via props
  useEffect(() => {
    if (isMarketAdmin && marketId) setSelectedMarket(marketId);
  }, [marketId, isMarketAdmin]);

  const getRentStatus = (vendor: Vendor) => {
    if (vendor.rentDue <= 0) {
      return { 
        label: 'PAID', 
        color: 'bg-emerald-500 shadow-[0_0_12px_rgba(16,185,129,0.6)]', 
        text: 'text-emerald-700', 
        bg: 'bg-emerald-50', 
        border: 'border-emerald-100' 
      };
    }
    const dueDate = vendor.rentDueDate ? new Date(vendor.rentDueDate) : null;
    const isOverdue = dueDate && dueDate < new Date();
    if (isOverdue) {
      return { 
        label: 'OVERDUE', 
        color: 'bg-rose-500 shadow-[0_0_12px_rgba(244,63,94,0.6)] animate-pulse', 
        text: 'text-rose-700', 
        bg: 'bg-rose-50', 
        border: 'border-rose-100' 
      };
    }
    return { 
      label: 'PENDING', 
      color: 'bg-amber-500 shadow-[0_0_12px_rgba(245,158,11,0.6)]', 
      text: 'text-amber-700', 
      bg: 'bg-amber-50', 
      border: 'border-amber-100' 
    };
  };

  const filteredAndSortedVendors = useMemo(() => {
    let result = vendors.filter(v => {
      const term = searchTerm.toLowerCase();
      const matchesSearch = v.name.toLowerCase().includes(term) || v.shopNumber.toLowerCase().includes(term);
      const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;

      // Strict Market RBAC Filtering
      let matchesMarket = true;
      if (isMarketAdmin && marketId) {
        matchesMarket = v.marketId === marketId;
      } else {
        matchesMarket = selectedMarket === 'ALL' || v.marketId === selectedMarket;
      }

      return matchesSearch && matchesStatus && matchesMarket;
    });

    if (nameSortOrder === 'A_Z') result = [...result].sort((a, b) => a.name.localeCompare(b.name));
    else if (nameSortOrder === 'Z_A') result = [...result].sort((a, b) => b.name.localeCompare(a.name));

    if (rentSortOrder === 'LOW_HIGH') result = [...result].sort((a, b) => a.rentDue - b.rentDue);
    else if (rentSortOrder === 'HIGH_LOW') result = [...result].sort((a, b) => b.rentDue - a.rentDue);

    return result;
  }, [vendors, searchTerm, statusFilter, selectedMarket, rentSortOrder, nameSortOrder, isMarketAdmin, marketId]);

  const toggleSelect = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === filteredAndSortedVendors.length && filteredAndSortedVendors.length > 0) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredAndSortedVendors.map(v => v.id)));
    }
  };

  const handleBulkAction = (action: 'ACTIVATE' | 'SUSPEND') => {
    if (selectedIds.size === 0) return;
    const nextStatus = action === 'ACTIVATE' ? 'ACTIVE' : 'SUSPENDED';
    setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, status: nextStatus as any } : v));
    setSelectedIds(new Set());
    alert(`Bulk Operation: ${selectedIds.size} entities transitioned to ${nextStatus}.`);
  };

  return (
    <div className="space-y-8 animate-in fade-in pb-24">
      {/* Module Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pb-6 border-b border-slate-200">
        <div className="flex items-center gap-6">
           <div className="w-20 h-20 bg-slate-950 text-white rounded-[32px] flex items-center justify-center shadow-2xl ring-4 ring-indigo-50">
             <Store size={36} className="text-indigo-400" />
           </div>
           <div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase leading-none">Vendor Ledger</h2>
              <div className="flex items-center gap-3 mt-3">
                 <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-indigo-100 flex items-center gap-2">
                    <ShieldCheck size={12}/> {isSuperAdmin ? 'Global Registry' : `Market Terminal: ${marketId || 'N/A'}`}
                 </span>
                 <p className="text-slate-400 font-bold text-sm tracking-tight">Node Access Management</p>
              </div>
           </div>
        </div>

        <div className="flex items-center gap-3">
          {isAdmin && selectedIds.size > 0 && (
            <div className="flex gap-2 animate-in slide-in-from-right-4">
               <button onClick={() => handleBulkAction('ACTIVATE')} className="flex items-center gap-3 bg-emerald-600 hover:bg-emerald-700 text-white px-6 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] shadow-xl transition-all">
                  <Play size={16}/> Activate All
               </button>
               <button onClick={() => handleBulkAction('SUSPEND')} className="flex items-center gap-3 bg-slate-950 hover:bg-black text-white px-6 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] shadow-xl transition-all">
                  <Ban size={16}/> Suspend All
               </button>
            </div>
          )}
          {isAdmin && (
            <Button className="h-14 px-10 font-black uppercase text-[11px] tracking-[0.2em] bg-indigo-600 hover:bg-indigo-700 shadow-2xl shadow-indigo-100 rounded-2xl">
              <UserPlus size={20} className="mr-3"/> Register Entity
            </Button>
          )}
        </div>
      </div>

      {/* Controls */}
      <div className="bg-white p-8 rounded-[48px] border border-slate-200 shadow-xl space-y-8">
