import React, { useState, useEffect } from 'react';
import { MOCK_TOKENS, MOCK_BIDS, MOCK_REQUISITIONS, MOCK_VENDORS, MARKETS } from '../constants';
import { GateToken, VehicleCategory, Bid, Requisition, Vendor, UserRole } from '../types';
import { Card } from './ui/Card';
import { Button } from './ui/Button';
import { 
  QrCode, CheckCircle, Truck, Search, DollarSign, ShieldAlert,
  Smartphone, ShieldCheck, X, Activity, Monitor, UserCheck, AlertTriangle
} from 'lucide-react';

interface GateManagementModuleProps {
  currentMarketId?: string;
  userRole?: UserRole;
}

export const GateManagementModule: React.FC<GateManagementModuleProps> = ({ currentMarketId = 'm1', userRole }) => {
  const [activeTab, setActiveTab] = useState<'TERMINAL' | 'VENDOR_TRIAGE' | 'EXIT' | 'LOGS'>('TERMINAL');
  const [isLoading, setIsLoading] = useState(false);
  const [vendorCode, setVendorCode] = useState('');
  const [scannedVendor, setScannedVendor] = useState<Vendor | null>(null);
  const [validationError, setValidationError] = useState<string | null>(null);

  const currentMarket = MARKETS.find(m => m.id === currentMarketId);

  const handleScanVendor = () => {
      if(!vendorCode) return;
      setIsLoading(true);
      setValidationError(null);

      setTimeout(() => {
          const match = MOCK_VENDORS.find(v => vendorCode.includes(v.id.toUpperCase())) || null;

          if (!match) {
            setValidationError("REGISTRY ERROR: Unique Node Identifier not triangulated.");
            setScannedVendor(null);
          } else if (match.marketId !== currentMarketId) {
            setValidationError(`ROUTING ALERT: Entity is registered to ${MARKETS.find(m => m.id === match.marketId)?.name}. ACCESS DENIED AT THIS HUB.`);
            setScannedVendor(match);
          } else {
            setScannedVendor(match);
          }
          setIsLoading(false);
      }, 800);
  };

  return (
    <div className="space-y-8 animate-in fade-in pb-20">
       <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 pb-6 border-b border-slate-200">
          <div className="flex items-center gap-6">
             <div className="w-20 h-20 bg-slate-950 text-white rounded-[32px] flex items-center justify-center shadow-2xl ring-4 ring-indigo-50">
                <Smartphone size={40} className="text-indigo-400" />
             </div>
             <div>
                <h2 className="text-4xl font-black text-slate-950 tracking-tighter uppercase leading-none">Terminal Console</h2>
                <p className="text-slate-500 font-medium text-lg mt-2 flex items-center gap-2">
                   <Monitor size={18} className="text-indigo-600" /> Hub: {currentMarket?.name || 'GENERIC-HUB'}
                </p>
             </div>
          </div>
          <div className="flex bg-slate-100 p-2 rounded-[28px] shadow-inner border border-slate-200 overflow-x-auto max-w-full">
             {[
                 { id: 'TERMINAL', label: 'Logistics', icon: Truck },
                 { id: 'VENDOR_TRIAGE', label: 'Vendor Scan', icon: UserCheck },
                 { id: 'EXIT', label: 'Outbound', icon: Activity }
             ].map(tab => (
                 <button 
                    key={tab.id}
                    onClick={() => { setActiveTab(tab.id as any); setScannedVendor(null); setValidationError(null); }} 
                    className={`px-8 py-3.5 rounded-[20px] text-[10px] font-black uppercase tracking-[0.2em] transition-all flex items-center gap-3 whitespace-nowrap ${activeTab === tab.id ? 'bg-white shadow-2xl text-indigo-600' : 'text-slate-500 hover:text-slate-900'}`}
                 >
                    <tab.icon size={16}/> {tab.label}
                 </button>
             ))}
          </div>
       </div>

       {activeTab === 'VENDOR_TRIAGE' && (
           <div className="max-w-3xl mx-auto space-y-8 animate-in slide-in-from-bottom-6">
                <Card className="p-12 rounded-[56px] bg-white shadow-2xl border-none text-center relative overflow-hidden">
                    <h3 className="text-3xl font-black text-slate-900 uppercase tracking-tighter mb-4">Node Authorization</h3>
                    <p className="text-slate-500 mb-10 font-medium max-w-md mx-auto">Validate registry status and fiscal compliance before granting hub access.</p>

                    <div className="flex gap-4 mb-10">
                        <div className="relative flex-1">
                            <QrCode className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={24} />
                            <input 
                                className="w-full pl-16 pr-6 py-6 rounded-[28px] bg-slate-50 border-4 border-slate-50 outline-none font-mono text-xl tracking-[0.2em] focus:border-indigo-600 focus:bg-white transition-all shadow-inner uppercase" 
                                placeholder="SCAN VENDOR KEY"
                                value={vendorCode}
                                onChange={e => setVendorCode(e.target.value.toUpperCase())}
                            />
                        </div>
                        <Button onClick={handleScanVendor} loading={isLoading} className="px-10 rounded-[28px] bg-slate-950 hover:bg-black font-black uppercase tracking-widest text-[10px]">Execute Sync</Button>
                    </div>

                    {validationError && (
                      <div className="bg-rose-50 border-2 border-rose-100 p-6 rounded-[32px] mb-8 flex items-start gap-4 text-left animate-in slide-in-from-top-2">
                        <ShieldAlert size={28} className="text-rose-600 shrink-0 mt-1" />
                        <div>
                          <p className="text-rose-700 font-black text-[11px] uppercase tracking-widest mb-1">Authorization Fault</p>
                          <p className="text-rose-600 text-sm font-bold leading-relaxed">{validationError}</p>
                        </div>
                      </div>
                    )}

                    {scannedVendor && !validationError && (
                        <div className="animate-in zoom-in-95 bg-slate-50 rounded-[40px] p-10 border-4 border-white shadow-inner space-y-8 text-left relative z-10">
                             <div className="flex justify-between items-start">
                                 <div>
                                    <p className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-2">Authenticated Registry Node</p>
                                    <h4 className="text-3xl font-black text-slate-900 tracking-tighter uppercase">{scannedVendor.name}</h4>
                                    <p className="text-sm font-bold text-slate-400 mt-1">Shop Node #{scannedVendor.shopNumber}</p>
                                 </div>
                                 <div className={`p-6 rounded-3xl shadow-lg flex flex-col items-center justify-center min-w-[140px] ${scannedVendor.status === 'ACTIVE' ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}>
                                    <span className="text-[10px] font-black uppercase tracking-widest opacity-60">Status</span>
                                    <span className="text-xl font-black uppercase tracking-tighter">{scannedVendor.status}</span>
                                 </div>
                             </div>

                             <div className="grid grid-cols-2 gap-6">
                                 <div className={`p-6 rounded-3xl border-2 ${scannedVendor.rentDue > 0 ? 'bg-rose-50 border-rose-100' : 'bg-emerald-50 border-emerald-100'}`}>
                                     <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Remittance Status</p>
                                     <p className={`text-2xl font-black ${scannedVendor.rentDue > 0 ? 'text-rose-700' : 'text-emerald-700'}`}>
                                         {scannedVendor.rentDue > 0 ? `UGX ${scannedVendor.rentDue.toLocaleString()} Arrears` : 'CLEAR'}
                                     </p>
                                 </div>
                                 <div className="p-6 bg-white rounded-3xl border-2 border-slate-100">
                                     <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Biometric KYC</p>
                                     <div className="flex items-center gap-2">
                                        <ShieldCheck className="text-indigo-600" size={24}/>
                                        <p className="text-xl font-black text-slate-900 uppercase tracking-tighter">VALIDATED</p>
                                     </div>
                                 </div>
                             </div>

                             <div className="flex gap-4">
                                <Button 
                                  disabled={scannedVendor.rentDue > 0 || scannedVendor.status !== 'ACTIVE'}
                                  className={`flex-1 h-20 rounded-[28px] font-black uppercase tracking-widest text-[11px] shadow-2xl transition-all ${scannedVendor.status === 'ACTIVE' && scannedVendor.rentDue <= 0 ? 'bg-emerald-600 hover:bg-emerald-700' : 'bg-slate-300 cursor-not-allowed grayscale'}`}
                                >
                                  Authorize Hub Entry
                                </Button>
                                <Button variant="secondary" onClick={() => { setScannedVendor(null); setVendorCode(''); }} className="h-20 w-20 rounded-[28px] p-0 border-2"><X size={24}/></Button>
                             </div>
                        </div>
                    )}
                </Card>
           </div>
       )}

       {activeTab === 'TERMINAL' && (
          <div className="text-center py-24 bg-slate-900/5 rounded-[48px] border-4 border-dashed border-slate-200">
             <Truck size={64} className="mx-auto text-slate-300 mb-6 opacity-40 animate-pulse"/>
             <p className="font-black text-slate-400 uppercase tracking-[0.4em] text-sm">Logistics Sync Terminal Ready</p>
          </div>
       )}
