  );
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Bot, User, Minimize2, Loader2 } from 'lucide-react';
import { ApiService } from '../services/api';
// Fix: Import GoogleGenAI from @google/genai
import { GoogleGenAI } from "@google/genai";

export const AIChatbot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{role: 'user' | 'model', text: string}[]>([
    { role: 'model', text: 'Hello! I am the MMIS Assistant. How can I help you manage your market operations today?' }
  ]);
  const [input, setInput] = useState('');
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsThinking(true);

    try {
      // Fix: Initialize GoogleGenAI SDK with the automatically injected API key
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // Fix: Use ai.models.generateContent to query the model with history
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...messages.filter((m, i) => i > 0 || m.role === 'user').map(m => ({
            role: m.role,
            parts: [{ text: m.text }]
          })),
          { role: 'user', parts: [{ text: userMsg }] }
        ],
        config: {
          systemInstruction: 'You are the MMIS Assistant. Help users manage market operations. Be concise and professional.',
        },
      });

      // Fix: Extract generated text from the response object
      setMessages(prev => [...prev, { 
        role: 'model', 
        text: response.text || "I received your message but couldn't generate a text response." 
      }]);
    } catch (error) {
      console.error("AI Service Error:", error);
      setMessages(prev => [...prev, { 
        role: 'model', 
        text: "I'm having trouble connecting to the neural core. Please check your connection." 
      }]);
    } finally {
      setIsThinking(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSend();
  };

  if (!isOpen) {
    return (
      <button 
        onClick={() => setIsOpen(true)}
        className="fixed bottom-6 right-6 p-4 bg-blue-600 hover:bg-blue-700 text-white rounded-full shadow-2xl transition-all hover:scale-110 z-50 flex items-center justify-center"
      >
        <MessageCircle size={24} />
      </button>
    );
  }

  return (
    <div className="fixed bottom-6 right-6 w-96 h-[500px] bg-white rounded-2xl shadow-2xl border border-slate-200 z-50 flex flex-col animate-in slide-in-from-bottom-10 fade-in">
      {/* Header */}
      <div className="p-4 bg-blue-600 text-white rounded-t-2xl flex justify-between items-center">
        <div className="flex items-center gap-2">
          <Bot size={20} />
          <span className="font-bold">MMIS Assistant</span>
        </div>
        <div className="flex items-center gap-2">
           <button onClick={() => setIsOpen(false)} className="hover:bg-blue-500 p-1 rounded transition">
             <Minimize2 size={16} />
           </button>
           <button onClick={() => setIsOpen(false)} className="hover:bg-blue-500 p-1 rounded transition">
             <X size={16} />
           </button>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50">
        {messages.map((m, idx) => (
          <div key={idx} className={`flex gap-2 ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
             <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${m.role === 'user' ? 'bg-slate-200' : 'bg-blue-100 text-blue-600'}`}>
                {m.role === 'user' ? <User size={14}/> : <Bot size={14}/>}
             </div>
             <div className={`p-3 rounded-lg text-sm max-w-[80%] shadow-sm ${
               m.role === 'user' ? 'bg-white border border-slate-200 text-slate-800 rounded-tr-none' : 'bg-blue-600 text-white rounded-tl-none'
             }`}>
               {m.text}
             </div>
          </div>
        ))}
        {isThinking && (
           <div className="flex gap-2">
              <div className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center shrink-0">
                  <Bot size={14}/>
              </div>
              <div className="p-3 rounded-lg bg-blue-600 text-white rounded-tl-none text-sm max-w-[80%] flex items-center gap-2">
                 <Loader2 size={14} className="animate-spin" /> Thinking...
              </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-white border-t border-slate-100 rounded-b-2xl">
        <div className="flex gap-2">
           <input 
              type="text" 
              className="flex-1 px-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              placeholder="Ask about vendors, gates..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyPress}
           />
           <button 
             onClick={handleSend}
             disabled={isThinking || !input.trim()}
             className="p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
           >
             <Send size={18} />
           </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { MOCK_TICKETS, MOCK_STAFF } from '../constants';
import { TicketPriority, TicketContext, UserRole, Ticket } from '../types';
import { AlertCircle, Wrench, MessageSquare, Package, Bot, Paperclip, Send, Lock, Plus, Search, UserPlus, Check, X } from 'lucide-react';
import { ApiService } from '../services/api';
// Fix: Import GoogleGenAI from @google/genai
import { GoogleGenAI } from "@google/genai";

interface TicketSystemProps {
  userRole?: UserRole;
  marketId?: string;
}

export const TicketSystem: React.FC<TicketSystemProps> = ({ userRole = UserRole.USER, marketId }) => {
  const [tickets, setTickets] = useState<Ticket[]>(MOCK_TICKETS);
  const [selectedTicketId, setSelectedTicketId] = useState<string | null>(null);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isLoadingSummary, setIsLoadingSummary] = useState(false);
  const [showCreateModal, setShowCreateModal] = useState(false);

  // Search State
  const [searchTerm, setSearchTerm] = useState('');

  // New Ticket Form State
  const [newTicket, setNewTicket] = useState({
    title: '',
    description: '',
    context: TicketContext.SUPPORT,
    priority: TicketPriority.MEDIUM,
    file: null as File | null
  });

  // RBAC Permissions
  const isSuperAdmin = userRole === UserRole.SUPER_ADMIN;
  const isMarketAdmin = userRole === UserRole.MARKET_ADMIN;
  // Admin privilege generally allows action, but scope is defined by marketId
  const canManageTickets = isSuperAdmin || isMarketAdmin;

  const filteredTickets = tickets.filter(t => {
     // 1. Scope Filter: 
     if (isSuperAdmin) {
         // See all
     } else if (isMarketAdmin) {
         if (t.marketId !== marketId) return false;
     } else {
         if (t.createdByRole !== userRole) return false; // Simplified mock logic
     }

     // 2. Search Filter
     const term = searchTerm.toLowerCase();
     const matchesSearch = !term || 
        t.title.toLowerCase().includes(term) || 
        (t.description && t.description.toLowerCase().includes(term)) ||
        t.id.toLowerCase().includes(term);

     return matchesSearch;
  });

  const selectedTicket = filteredTickets.find(t => t.id === selectedTicketId) || filteredTickets[0];

  const getPriorityColor = (p: TicketPriority) => {
    switch (p) {
      case TicketPriority.CRITICAL: return 'bg-red-100 text-red-700 border-red-200';
      case TicketPriority.HIGH: return 'bg-orange-100 text-orange-700 border-orange-200';
      case TicketPriority.MEDIUM: return 'bg-blue-100 text-blue-700 border-blue-200';
      default: return 'bg-slate-100 text-slate-700 border-slate-200';
    }
  };

  const getContextIcon = (c: TicketContext) => {
    switch (c) {
      case TicketContext.ASSET: return <Wrench size={16} />;
      case TicketContext.SUPPLY: return <Package size={16} />;
      case TicketContext.COMPLAINT: return <AlertCircle size={16} />;
      default: return <MessageSquare size={16} />;
    }
  };

  const generateSummary = async (description: string) => {
    setIsLoadingSummary(true);
    try {
      // Fix: Use GoogleGenAI SDK directly instead of calling a remote BFF
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Summarize the following support ticket description for a market administrator: ${description}`,
        config: {
          systemInstruction: 'You are an AI assistant helping market administrators by providing concise summaries of reported issues.',
        }
      });
      // Fix: Access response text property directly
      setAiSummary(response.text || "Summary generated.");
    } catch (error) {
      console.warn("AI Service unavailable, falling back to mock.");
      // Fallback for demo if backend is offline
      setTimeout(() => {
        setAiSummary("Based on the report, this requires immediate maintenance. The asset is critical to daily operations.");
      }, 1000);
    } finally {
      setIsLoadingSummary(false);
    }
  };

  const handleCreateTicket = () => {
    if (!newTicket.title || !newTicket.description) {
        alert("Please fill in title and description.");
        return;
    }

    const created: Ticket = {
        id: `t${Date.now()}`,
        title: newTicket.title,
        description: newTicket.description,
        context: newTicket.context,
        priority: newTicket.priority,
        status: 'OPEN',
        createdAt: new Date().toISOString(),
        createdByRole: userRole,
        marketId: marketId || 'm1', // Assign ticket to current user's market context
        attachmentUrl: newTicket.file ? newTicket.file.name : undefined
    };

    setTickets([created, ...tickets]);
    setShowCreateModal(false);
    setNewTicket({ title: '', description: '', context: TicketContext.SUPPORT, priority: TicketPriority.MEDIUM, file: null });
    setSelectedTicketId(created.id);
  };

  const handleAssignTicket = (staffName: string) => {
      if (!selectedTicket) return;
      const updatedTickets = tickets.map(t => 
          t.id === selectedTicket.id 
          ? { ...t, status: 'ASSIGNED' as const, assignedTo: staffName } 
          : t
      );
      setTickets(updatedTickets);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-8rem)]">
        <div className="flex justify-between items-center mb-4">
             <h2 className="text-xl font-bold text-slate-800">Support & Tickets</h2>
             <button 
                onClick={() => setShowCreateModal(true)}
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2"
             >
                <Plus size={16} /> New Ticket
             </button>
        </div>

        {/* Search Bar */}
        <div className="mb-4 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
                type="text" 
                placeholder="Search tickets by ID, title, or description..."
                className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
            />
        </div>

    <div className="flex flex-1 gap-6 overflow-hidden">
      {/* Ticket List */}
      <div className="w-1/3 flex flex-col gap-4 overflow-y-auto pr-2 pb-10">
        {filteredTickets.length === 0 ? (
             <div className="p-8 text-center bg-white rounded-xl border border-slate-200">
                <p className="text-slate-500">No tickets found{searchTerm ? ` matching "${searchTerm}"` : ''}.</p>
             </div>
        ) : (
            filteredTickets.map(ticket => (
            <div 
                key={ticket.id} 
                onClick={() => { setSelectedTicketId(ticket.id); setAiSummary(''); }}
                className={`p-4 rounded-xl border shadow-sm cursor-pointer transition-all ${
                (selectedTicket && selectedTicket.id === ticket.id)
                    ? 'bg-blue-50 border-blue-200 ring-1 ring-blue-300' 
                    : 'bg-white border-slate-200 hover:shadow-md'
                }`}
            >
                <div className="flex justify-between items-start mb-2">
                <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase border ${getPriorityColor(ticket.priority)}`}>
                    {ticket.priority}
                </span>
                <span className="text-xs text-slate-400">{new Date(ticket.createdAt).toLocaleDateString()}</span>
                </div>
                <h4 className="font-semibold text-slate-800 mb-1 text-sm">{ticket.title}</h4>
                <div className="flex items-center gap-2 text-xs text-slate-500">
                {getContextIcon(ticket.context)}
                <span>{ticket.context}</span>
                {ticket.status === 'ASSIGNED' && <span className="bg-slate-100 px-1 rounded text-[10px]">Assigned</span>}
                </div>
            </div>
            ))
        )}
      </div>

      {/* Detail / AI View */}
      <div className="w-2/3 bg-white rounded-xl border border-slate-200 shadow-sm flex flex-col overflow-hidden">
        {selectedTicket ? (
          <>
            <div className="p-4 bg-slate-50 border-b border-slate-200 flex items-center justify-between">
              <div className="flex items-center gap-3">
                 <div className={`p-2 rounded-lg ${getPriorityColor(selectedTicket.priority)}`}>
                    {getContextIcon(selectedTicket.context)}
                 </div>
                 <div>
                    <h3 className="font-bold text-slate-800 text-lg leading-none">{selectedTicket.title}</h3>
                    <p className="text-xs text-slate-500 mt-1">Ticket ID: {selectedTicket.id}</p>
                 </div>
              </div>

              <div className="flex gap-2">
                  {canManageTickets && selectedTicket.status === 'OPEN' && (
                      <div className="relative group">
                          <button className="flex items-center gap-2 text-blue-700 text-xs font-bold px-3 py-1.5 bg-blue-50 hover:bg-blue-100 rounded-full border border-blue-200 transition-colors">
                              <UserPlus size={14} /> Assign
                          </button>
                          {/* Assignment Dropdown */}
                          <div className="absolute right-0 top-full mt-2 w-48 bg-white border border-slate-200 rounded-xl shadow-xl hidden group-hover:block z-20 overflow-hidden">
                              <div className="px-4 py-2 text-[10px] font-bold uppercase text-slate-400 bg-slate-50">Staff List</div>
                              {MOCK_STAFF.map(staff => (
                                  <button 
                                    key={staff.id} 
                                    onClick={() => handleAssignTicket(staff.name)}
                                    className="w-full text-left px-4 py-2 text-sm hover:bg-slate-50 text-slate-700"
                                  >
                                      {staff.name} ({staff.role})
                                  </button>
                              ))}
                          </div>
                      </div>
                  )}
                  {canManageTickets && (
                    <button 
                        onClick={() => generateSummary(selectedTicket.description || selectedTicket.title)}
                        disabled={isLoadingSummary}
                        className="flex items-center gap-2 text-purple-700 text-xs font-bold px-3 py-1.5 bg-purple-50 hover:bg-purple-100 rounded-full border border-purple-200 transition-colors"
                    >
                        <Bot size={14} /> 
                        {isLoadingSummary ? 'Analyzing...' : 'Generate AI Summary'}
                    </button>
                  )}
              </div>
            </div>

            <div className="p-6 flex-1 overflow-y-auto">
               {/* AI Summary Section - Admin Only */}
               {(aiSummary && canManageTickets) && (
                 <div className="mb-6 bg-gradient-to-r from-purple-50 to-white p-4 rounded-lg border border-purple-100 animate-in fade-in slide-in-from-top-2">
                   <div className="flex items-center gap-2 mb-2 text-purple-700 font-medium text-sm">
                      <Bot size={16} />
                      <span>Gemini Insight</span>
                   </div>
                   <p className="text-sm text-slate-700 leading-relaxed italic">
                     "{aiSummary}"
                   </p>
                 </div>
               )}

               {/* Description */}
               <div className="mb-8">
                  <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Issue Description</h4>
                  <p className="text-slate-800 text-sm leading-relaxed bg-slate-50 p-4 rounded-lg border border-slate-100">
                    {selectedTicket.description || "No detailed description provided."}
                  </p>
                  {selectedTicket.attachmentUrl && (
                      <div className="mt-3 flex items-center gap-2 text-sm text-blue-600 bg-blue-50 p-2 rounded-lg w-fit border border-blue-100 cursor-pointer hover:bg-blue-100">
                          <Paperclip size={14} /> {selectedTicket.attachmentUrl}
                      </div>
                  )}
               </div>

               {/* Chat Thread Mock */}
               <div className="space-y-4">
                 <div className="flex gap-3">
                   <div className="w-8 h-8 rounded-full bg-slate-200 flex-shrink-0 flex items-center justify-center text-xs font-bold text-slate-600">
                       {selectedTicket.createdByRole ? selectedTicket.createdByRole[0] : 'U'}
                   </div>
                   <div className="bg-slate-100 p-3 rounded-lg rounded-tl-none text-sm text-slate-700 shadow-sm max-w-[80%]">
                     Reported the issue. Waiting for assignment.
                   </div>
                 </div>
                 {selectedTicket.assignedTo && (
                   <div className="flex gap-3 flex-row-reverse">
                     <div className="w-8 h-8 rounded-full bg-blue-100 flex-shrink-0 flex items-center justify-center text-xs font-bold text-blue-600">A</div>
                     <div className="bg-blue-600 text-white p-3 rounded-lg rounded-tr-none text-sm shadow-sm max-w-[80%]">
                       I'm on it. {selectedTicket.assignedTo} assigned.
                     </div>
                   </div>
                 )}
               </div>
            </div>

            <div className="p-4 border-t border-slate-200 bg-slate-50">
               {canManageTickets ? (
                <div className="flex gap-2">
                    <button className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-200 rounded-lg transition-colors">
                    <Paperclip size={20} />
                    </button>
                    <input 
                    type="text" 
                    placeholder="Type a reply or internal note..." 
                    className="flex-1 px-4 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                    />
                    <button className="p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors shadow-sm">
                    <Send size={18} />
                    </button>
                </div>
               ) : (
                   <div className="flex items-center justify-center text-slate-500 text-xs gap-2">
                       <Lock size={12} /> Thread is read-only. Updates are managed by Admin.
                   </div>
               )}
            </div>
          </>
        ) : (
             <div className="flex flex-col items-center justify-center h-full text-slate-400">
                 <MessageSquare size={48} className="mb-4 opacity-20"/>
                 <p>Select a ticket to view details</p>
             </div>
        )}
      </div>
    </div>

    {/* Create Modal */}
    {showCreateModal && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-lg">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-lg font-bold text-slate-900">Create New Ticket</h3>
                    <button onClick={() => setShowCreateModal(false)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                </div>
                <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Title</label>
                        <input 
                            type="text" 
                            className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                            value={newTicket.title}
                            onChange={(e) => setNewTicket({...newTicket, title: e.target.value})}
                        />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Context</label>
                            <select 
                                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                                value={newTicket.context}
                                onChange={(e) => setNewTicket({...newTicket, context: e.target.value as TicketContext})}
                            >
                                {Object.values(TicketContext).map(c => <option key={c} value={c}>{c}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Priority</label>
                            <select 
                                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                                value={newTicket.priority}
                                onChange={(e) => setNewTicket({...newTicket, priority: e.target.value as TicketPriority})}
                            >
                                {Object.values(TicketPriority).map(p => <option key={p} value={p}>{p}</option>)}
                            </select>
                        </div>
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Description</label>
                        <textarea 
                            className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none h-32 resize-none"
                            value={newTicket.description}
                            onChange={(e) => setNewTicket({...newTicket, description: e.target.value})}
                        ></textarea>
                    </div>

                    {/* File Attachment Input */}
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Attachment</label>
                        <div className="flex items-center gap-2">
                            <label className="cursor-pointer flex items-center gap-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 rounded-lg text-sm text-slate-600 transition-colors border border-slate-200">
                                <Paperclip size={16} /> 
                                {newTicket.file ? 'Change File' : 'Attach File'}
                                <input 
                                    type="file" 
                                    className="hidden" 
                                    onChange={(e) => {
                                        if(e.target.files?.[0]) setNewTicket({...newTicket, file: e.target.files[0]});
                                    }}
                                />
                            </label>
                            {newTicket.file && <span className="text-xs text-blue-600 font-bold">{newTicket.file.name}</span>}
                        </div>
                    </div>

                    <div className="flex gap-3 pt-2">
                        <button onClick={() => setShowCreateModal(false)} className="flex-1 py-2 text-slate-500 hover:bg-slate-50 rounded-lg font-medium">Cancel</button>
                        <button onClick={handleCreateTicket} className="flex-1 py-2 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700">Submit Ticket</button>
                    </div>
                </div>
            </div>
        </div>
    )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Vendor, UserRole, ProductCategory } from '../types';
import { MOCK_VENDORS, MARKETS } from '../constants';
import { 
  Search, QrCode, UserPlus, Store, ArrowUpDown, 
  ShieldCheck, Play, Ban, X, Download, Printer, Filter, 
  CheckSquare, Square, DollarSign, ListFilter, MoreVertical,
  Building2, MapPin, User, ChevronDown, ExternalLink, Trash2,
  AlertCircle, CheckCircle2
} from 'lucide-react';
import { Button } from './ui/Button';
import { VendorDetailsModal } from './VendorDetailsModal';

interface VendorModuleProps {
  userRole?: UserRole;
  currentUserId?: string;
  marketId?: string;
}

export const VendorModule: React.FC<VendorModuleProps> = ({ 
  userRole = UserRole.USER, 
  currentUserId, 
  marketId 
}) => {
  const [vendors, setVendors] = useState<Vendor[]>(MOCK_VENDORS);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [searchTerm, setSearchTerm] = useState('');

  const isSuperAdmin = userRole === UserRole.SUPER_ADMIN;
  const isMarketAdmin = userRole === UserRole.MARKET_ADMIN;
  const isAdmin = isSuperAdmin || isMarketAdmin;

  const initialMarket = isMarketAdmin ? marketId : 'ALL';
  const [selectedMarket, setSelectedMarket] = useState(initialMarket || 'ALL');
  const [statusFilter, setStatusFilter] = useState('ALL');

  const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(null);
  const [qrModalVendor, setQrModalVendor] = useState<Vendor | null>(null);

  // Computed: Filtered list for display and bulk logic
  const filteredVendors = useMemo(() => {
    return vendors.filter(v => {
      const term = searchTerm.toLowerCase();
      const matchesSearch = v.name.toLowerCase().includes(term) || v.shopNumber.toLowerCase().includes(term);
      const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;

      let matchesMarket = true;
      if (isMarketAdmin) {
        matchesMarket = v.marketId === marketId;
      } else {
        matchesMarket = selectedMarket === 'ALL' || v.marketId === selectedMarket;
      }

      return matchesSearch && matchesStatus && matchesMarket;
    });
  }, [vendors, searchTerm, statusFilter, selectedMarket, isMarketAdmin, marketId]);

  // Selection Logic
  const isAllSelected = useMemo(() => {
    return filteredVendors.length > 0 && filteredVendors.every(v => selectedIds.has(v.id));
  }, [filteredVendors, selectedIds]);

  const toggleSelectAll = () => {
    const next = new Set(selectedIds);
    if (isAllSelected) {
      filteredVendors.forEach(v => next.delete(v.id));
    } else {
      filteredVendors.forEach(v => next.add(v.id));
    }
    setSelectedIds(next);
  };

  const toggleSelect = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const handleBulkAction = (action: 'ACTIVATE' | 'SUSPEND' | 'DELETE') => {
    if (selectedIds.size === 0) return;

    if (action === 'DELETE') {
      if (!isSuperAdmin) {
        alert("RBAC SECURITY: Mass Registry Nullification is exclusive to Super Admin level.");
        return;
      }
      if (!confirm(`CAUTION: Permanently purge ${selectedIds.size} entities from the registry? This action is irreversible.`)) return;
      setVendors(prev => prev.filter(v => !selectedIds.has(v.id)));
    } else {
      const nextStatus = action === 'ACTIVATE' ? 'ACTIVE' : 'SUSPENDED';
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, status: nextStatus as any } : v));
    }

    setSelectedIds(new Set());
  };

  return (
    <div className="space-y-8 animate-in fade-in pb-32">
      {/* Module Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pb-6 border-b border-slate-200">
        <div className="flex items-center gap-6">
           <div className="w-20 h-20 bg-slate-950 text-white rounded-[32px] flex items-center justify-center shadow-2xl ring-4 ring-indigo-50">
             <Store size={36} className="text-indigo-400" />
           </div>
           <div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase leading-none">Vendor Registry</h2>
              <div className="flex items-center gap-3 mt-3">
                 <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-indigo-100 flex items-center gap-2">
                    <ShieldCheck size={12}/> {isSuperAdmin ? 'Global Treasury' : `Hub Terminal: ${marketId}`}
                 </span>
                 <p className="text-slate-400 font-bold text-sm tracking-tight uppercase tracking-widest">Node Operations Matrix</p>
              </div>
           </div>
        </div>

        {isAdmin && (
          <Button className="h-14 px-10 font-black uppercase text-[11px] tracking-[0.2em] bg-indigo-600 hover:bg-indigo-700 shadow-2xl rounded-2xl transition-all active:scale-95">
            <UserPlus size={20} className="mr-3"/> Enroll Entity
          </Button>
        )}
      </div>

      {/* Control Surface */}
      <div className="bg-white p-8 rounded-[48px] border border-slate-200 shadow-xl space-y-8">
        <div className="flex flex-wrap gap-6 items-end">
          <div className="relative flex-1 min-w-[320px]">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={24} />
            <input 
              type="text" 
              placeholder="Query node identity, unit, or UID..." 
              className="w-full pl-16 pr-8 py-5 rounded-[28px] border-4 border-slate-50 bg-slate-50 font-bold text-sm text-slate-950 focus:bg-white focus:border-indigo-600 outline-none transition-all shadow-inner"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Market Scope</label>
                <div className="relative">
                  <select 
                    disabled={isMarketAdmin}
                    className={`px-6 py-4 border-2 border-slate-100 rounded-[22px] text-[10px] font-black uppercase tracking-widest bg-slate-50 outline-none appearance-none transition-all min-w-[200px] cursor-pointer ${isMarketAdmin ? 'opacity-50 grayscale' : 'hover:border-indigo-600'}`}
                    value={selectedMarket} 
                    onChange={(e) => setSelectedMarket(e.target.value)}
                  >
                      {isSuperAdmin && <option value="ALL">Global Registry</option>}
                      {MARKETS.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                  <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                </div>
              </div>
          </div>
        </div>
      </div>

      {/* Registry Matrix */}
      <div className="bg-white rounded-[64px] border border-slate-200 shadow-2xl overflow-hidden relative">
        <table className="w-full text-sm text-left">
          <thead className="bg-slate-950 text-indigo-400 font-black uppercase text-[11px] tracking-[0.4em] border-b border-slate-900">
            <tr>
              <th className="px-10 py-10 w-10">
                <button 
                  onClick={toggleSelectAll}
                  className={`transition-all ${isAllSelected ? 'text-white' : 'text-indigo-400 hover:text-white'}`}
                >
                  {isAllSelected ? <CheckSquare size={24}/> : <Square size={24}/>}
                </button>
              </th>
              <th className="px-10 py-10">Registry Node</th>
              <th className="px-10 py-10">Unit Node</th>
              <th className="px-10 py-10">Status</th>
              <th className="px-10 py-10 text-right">Node Protocol</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredVendors.map(vendor => {
              const isSelected = selectedIds.has(vendor.id);
              return (
                <tr 
                  key={vendor.id} 
                  className={`hover:bg-indigo-50/40 transition-all group cursor-pointer border-l-4 ${isSelected ? 'bg-indigo-50/60 border-l-indigo-600' : 'border-l-transparent'}`} 
                  onClick={() => setSelectedVendor(vendor)}
                >
                  <td className="px-10 py-8" onClick={(e) => toggleSelect(vendor.id, e)}>
                    <button className={`transition-colors ${isSelected ? 'text-indigo-600' : 'text-slate-200 group-hover:text-indigo-300'}`}>
                       {isSelected ? <CheckSquare size={24}/> : <Square size={24}/>}
                    </button>
                  </td>
                  <td className="px-10 py-8">
                    <div className="font-black text-slate-950 uppercase tracking-tight text-base leading-none group-hover:text-indigo-600 transition-colors">{vendor.name}</div>
                    <div className="text-[10px] text-slate-400 font-bold mt-2 tracking-widest uppercase">ID: {vendor.id}</div>
                  </td>
                  <td className="px-10 py-8">
                      <div className="font-mono text-xs font-black text-slate-800 tracking-[0.2em]">#{vendor.shopNumber}</div>
                      <div className="text-[10px] text-slate-400 uppercase font-black tracking-widest mt-2 flex items-center gap-1.5">
                         <MapPin size={10}/> {MARKETS.find(m => m.id === vendor.marketId)?.name}
                      </div>
                  </td>
                  <td className="px-10 py-8">
                     <span className={`px-5 py-2 rounded-full text-[9px] font-black uppercase tracking-widest border-2 transition-all ${vendor.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                        {vendor.status}
                     </span>
                  </td>
                  <td className="px-10 py-8 text-right" onClick={(e) => e.stopPropagation()}>
                      <button 
                        onClick={() => setQrModalVendor(vendor)}
                        className="flex items-center gap-3 ml-auto px-6 py-3 bg-slate-950 hover:bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg group/qr"
                      >
                        <QrCode size={16} className="group-hover/qr:scale-110 transition-transform" />
                        <span>Issue Token</span>
                      </button>
                  </td>
                </tr>
              );
            })}
            {filteredVendors.length === 0 && (
              <tr>
                <td colSpan={5} className="px-10 py-32 text-center text-slate-400 bg-slate-50/50">
                  <Store size={64} className="mx-auto mb-6 opacity-10" />
                  <p className="font-black uppercase tracking-[0.4em] text-sm text-slate-950">No Entities Triangulated</p>
                  <p className="text-xs font-bold uppercase tracking-widest mt-2">Adjust registry filters or search parameters</p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Floating Bulk Action Bar */}
      {selectedIds.size > 0 && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] w-full max-w-4xl px-4 animate-in slide-in-from-bottom-10">
           <div className="bg-slate-950 text-white rounded-[32px] p-6 shadow-[0_40px_80px_rgba(0,0,0,0.5)] border-4 border-slate-900 flex items-center justify-between gap-8">
              <div className="flex items-center gap-6 pl-4 border-l-4 border-indigo-600">
                 <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-xl">
                    {selectedIds.size}
                 </div>
                 <div>
                    <p className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-400">Entities Selected</p>
                    <p className="text-sm font-bold text-slate-400">Perform Mass Ledger Transition</p>
                 </div>
              </div>

              <div className="flex gap-3">
                 <button 
                  onClick={() => handleBulkAction('ACTIVATE')}
                  className="flex items-center gap-3 bg-emerald-600 hover:bg-emerald-700 px-8 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                 >
                    <Play size={16}/> Activate All
                 </button>
                 <button 
                  onClick={() => handleBulkAction('SUSPEND')}
                  className="flex items-center gap-3 bg-amber-600 hover:bg-amber-700 px-8 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                 >
                    <Ban size={16}/> Suspend All
                 </button>
                 {isSuperAdmin && (
                   <button 
                    onClick={() => handleBulkAction('DELETE')}
                    className="flex items-center gap-3 bg-rose-600 hover:bg-rose-700 px-8 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                   >
                      <Trash2 size={16}/> Purge All
                   </button>
                 )}
                 <div className="w-px bg-slate-800 h-10 mx-2 self-center"></div>
                 <button 
                  onClick={() => setSelectedIds(new Set())}
                  className="p-4 hover:bg-slate-900 text-slate-500 hover:text-white rounded-2xl transition-colors"
                 >
                    <X size={24}/>
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* QR Modal (Simplified) */}
      {qrModalVendor && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-2xl z-[200] flex items-center justify-center p-4 animate-in fade-in">
           <div className="bg-white rounded-[72px] shadow-2xl max-w-md w-full p-16 text-center relative overflow-hidden group">
              <div className="absolute top-0 left-0 w-full h-3 bg-indigo-600"></div>
              <button onClick={() => setQrModalVendor(null)} className="absolute top-10 right-10 text-slate-300 hover:text-slate-950 transition-all hover:rotate-90 duration-500"><X size={44}/></button>

              <div className="mb-12">
                <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 shadow-2xl ring-8 ring-white">
                  <ShieldCheck size={48} />
                </div>
                <h3 className="text-3xl font-black text-slate-900 tracking-tighter uppercase leading-none mb-3">Operator Token</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-[0.2em]">{qrModalVendor.name}</p>
              </div>

              <div className="bg-slate-950 p-12 rounded-[56px] shadow-2xl mb-12 border-4 border-slate-900 flex flex-col items-center justify-center">
                 <div className="bg-white p-6 rounded-[40px] shadow-inner relative z-10">
                    <QrCode size={180} className="text-slate-900" />
                 </div>
                 <p className="text-indigo-400 mt-10 font-mono font-black tracking-[0.4em] text-sm uppercase">KEY-{qrModalVendor.id.toUpperCase()}</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <Button variant="secondary" className="h-16 rounded-3xl font-black uppercase text-[10px] tracking-widest border-4 border-slate-50 hover:bg-slate-50 transition-all"><Printer size={18} className="mr-3"/> Print</Button>
                 <Button className="h-16 rounded-3xl font-black uppercase text-[10px] tracking-widest shadow-xl bg-indigo-600 border-none transition-all active:scale-95"><Download size={18} className="mr-3"/> Export</Button>
              </div>
           </div>
        </div>
      )}

      {selectedVendor && (
        <VendorDetailsModal 
          vendor={selectedVendor} 
          userRole={userRole} 
          onClose={() => setSelectedVendor(null)} 
          onUpdateVendor={(u) => setVendors(prev => prev.map(v => v.id === u.id ? u : v))} 
        />
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Vendor, UserRole, ProductCategory } from '../types';
import { MOCK_VENDORS, MARKETS } from '../constants';
import { 
  Search, QrCode, UserPlus, Store, ArrowUpDown, 
  ShieldCheck, Play, Ban, X, Download, Printer, Filter, 
  CheckSquare, Square, DollarSign, ListFilter, MoreVertical,
  Building2, MapPin, User, ChevronDown, ExternalLink, Trash2,
  AlertCircle, CheckCircle2, FileJson, CalendarCheck, CreditCard,
  SortAsc, SortDesc
} from 'lucide-react';
import { Button } from './ui/Button';
import { VendorDetailsModal } from './VendorDetailsModal';

interface VendorModuleProps {
  userRole?: UserRole;
  currentUserId?: string;
  marketId?: string;
}

type SortConfig = {
  key: 'market' | 'name' | 'rent' | null;
  direction: 'asc' | 'desc';
};

export const VendorModule: React.FC<VendorModuleProps> = ({ 
  userRole = UserRole.USER, 
  currentUserId, 
  marketId 
}) => {
  const [vendors, setVendors] = useState<Vendor[]>(MOCK_VENDORS);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: null, direction: 'asc' });

  const isSuperAdmin = userRole === UserRole.SUPER_ADMIN;
  const isMarketAdmin = userRole === UserRole.MARKET_ADMIN;
  const isAdmin = isSuperAdmin || isMarketAdmin;

  const initialMarket = isMarketAdmin ? marketId : 'ALL';
  const [selectedMarket, setSelectedMarket] = useState(initialMarket || 'ALL');
  const [statusFilter, setStatusFilter] = useState('ALL');

  const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(null);
  const [qrModalVendor, setQrModalVendor] = useState<Vendor | null>(null);

  // Computed: Filtered and Sorted list for display and bulk logic
  const filteredVendors = useMemo(() => {
    let result = vendors.filter(v => {
      const term = searchTerm.toLowerCase();
      const matchesSearch = v.name.toLowerCase().includes(term) || v.shopNumber.toLowerCase().includes(term);
      const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;

      let matchesMarket = true;
      if (isMarketAdmin) {
        matchesMarket = v.marketId === marketId;
      } else {
        matchesMarket = selectedMarket === 'ALL' || v.marketId === selectedMarket;
      }

      return matchesSearch && matchesStatus && matchesMarket;
    });

    // Sorting Logic
    if (sortConfig.key) {
      result.sort((a, b) => {
        let valA: any;
        let valB: any;

        if (sortConfig.key === 'market') {
          valA = MARKETS.find(m => m.id === a.marketId)?.name || '';
          valB = MARKETS.find(m => m.id === b.marketId)?.name || '';
        } else if (sortConfig.key === 'rent') {
          valA = a.rentDue;
          valB = b.rentDue;
        } else {
          valA = a.name;
          valB = b.name;
        }

        if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }

    return result;
  }, [vendors, searchTerm, statusFilter, selectedMarket, isMarketAdmin, marketId, sortConfig]);

  const handleSort = (key: SortConfig['key']) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const exportToCSV = () => {
    const headers = ['ID', 'Name', 'Shop', 'Market', 'Status', 'Rent Due', 'Due Date'];
    const rows = filteredVendors.map(v => [
      v.id,
      v.name,
      v.shopNumber,
      MARKETS.find(m => m.id === v.marketId)?.name || 'Unknown',
      v.status,
      v.rentDue,
      v.rentDueDate || 'N/A'
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `vendor_export_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Selection Logic
  const isAllSelected = useMemo(() => {
    return filteredVendors.length > 0 && filteredVendors.every(v => selectedIds.has(v.id));
  }, [filteredVendors, selectedIds]);

  const toggleSelectAll = () => {
    const next = new Set(selectedIds);
    if (isAllSelected) {
      filteredVendors.forEach(v => next.delete(v.id));
    } else {
      filteredVendors.forEach(v => next.add(v.id));
    }
    setSelectedIds(next);
  };

  const toggleSelect = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const handleBulkAction = (action: 'ACTIVATE' | 'SUSPEND' | 'DELETE' | 'MARK_PAID' | 'SET_DUE_DATE') => {
    if (selectedIds.size === 0) return;

    if (action === 'DELETE') {
      if (!isSuperAdmin) {
        alert("RBAC SECURITY: Mass Registry Nullification is exclusive to Super Admin level.");
        return;
      }
      if (!confirm(`CAUTION: Permanently purge ${selectedIds.size} entities from the registry? This action is irreversible.`)) return;
      setVendors(prev => prev.filter(v => !selectedIds.has(v.id)));
    } else if (action === 'MARK_PAID') {
      if (!confirm(`Confirm: Mark rent as PAID for ${selectedIds.size} selected vendors?`)) return;
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, rentDue: 0 } : v));
    } else if (action === 'SET_DUE_DATE') {
      const date = prompt('Input Global Rent Due Date (YYYY-MM-DD):', new Date().toISOString().split('T')[0]);
      if (!date) return;
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, rentDueDate: date } : v));
    } else {
      const nextStatus = action === 'ACTIVATE' ? 'ACTIVE' : 'SUSPENDED';
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, status: nextStatus as any } : v));
    }

    setSelectedIds(new Set());
  };

  return (
    <div className="space-y-8 animate-in fade-in pb-32">
      {/* Module Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pb-6 border-b border-slate-200">
        <div className="flex items-center gap-6">
           <div className="w-20 h-20 bg-slate-950 text-white rounded-[32px] flex items-center justify-center shadow-2xl ring-4 ring-indigo-50">
             <Store size={36} className="text-indigo-400" />
           </div>
           <div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase leading-none">Vendor Registry</h2>
              <div className="flex items-center gap-3 mt-3">
                 <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-indigo-100 flex items-center gap-2">
                    <ShieldCheck size={12}/> {isSuperAdmin ? 'Global Treasury' : `Hub Terminal: ${marketId}`}
                 </span>
                 <p className="text-slate-400 font-bold text-sm tracking-tight uppercase tracking-widest">Node Operations Matrix</p>
              </div>
           </div>
        </div>

        <div className="flex items-center gap-3">
          <Button 
            variant="outline" 
            onClick={exportToCSV}
            className="h-14 px-8 border-2 font-black uppercase text-[11px] tracking-widest rounded-2xl bg-white transition-all hover:bg-slate-50"
          >
            <Download size={18} className="mr-2 text-slate-400"/> Export CSV
          </Button>
          {isAdmin && (
            <Button className="h-14 px-10 font-black uppercase text-[11px] tracking-[0.2em] bg-indigo-600 hover:bg-indigo-700 shadow-2xl rounded-2xl transition-all active:scale-95">
              <UserPlus size={20} className="mr-3"/> Enroll Entity
            </Button>
          )}
        </div>
      </div>

      {/* Control Surface */}
      <div className="bg-white p-8 rounded-[48px] border border-slate-200 shadow-xl space-y-8">
        <div className="flex flex-wrap gap-6 items-end">
          <div className="relative flex-1 min-w-[320px]">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={24} />
            <input 
              type="text" 
              placeholder="Query node identity, unit, or UID..." 
              className="w-full pl-16 pr-8 py-5 rounded-[28px] border-4 border-slate-50 bg-slate-50 font-bold text-sm text-slate-950 focus:bg-white focus:border-indigo-600 outline-none transition-all shadow-inner"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Market Scope</label>
                <div className="relative">
                  <select 
                    disabled={isMarketAdmin}
                    className={`px-6 py-4 border-2 border-slate-100 rounded-[22px] text-[10px] font-black uppercase tracking-widest bg-slate-50 outline-none appearance-none transition-all min-w-[200px] cursor-pointer ${isMarketAdmin ? 'opacity-50 grayscale' : 'hover:border-indigo-600'}`}
                    value={selectedMarket} 
                    onChange={(e) => setSelectedMarket(e.target.value)}
                  >
                      {isSuperAdmin && <option value="ALL">Global Registry</option>}
                      {MARKETS.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                  <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                </div>
              </div>
          </div>
        </div>
      </div>

      {/* Registry Matrix */}
      <div className="bg-white rounded-[64px] border border-slate-200 shadow-2xl overflow-hidden relative">
        <table className="w-full text-sm text-left">
          <thead className="bg-slate-950 text-indigo-400 font-black uppercase text-[11px] tracking-[0.4em] border-b border-slate-900">
            <tr>
              <th className="px-10 py-10 w-10">
                <button 
                  onClick={toggleSelectAll}
                  className={`transition-all ${isAllSelected ? 'text-white' : 'text-indigo-400 hover:text-white'}`}
                >
                  {isAllSelected ? <CheckSquare size={24}/> : <Square size={24}/>}
                </button>
              </th>
              <th className="px-10 py-10 cursor-pointer group" onClick={() => handleSort('name')}>
                <div className="flex items-center gap-2">
                  Registry Node
                  {sortConfig.key === 'name' ? (sortConfig.direction === 'asc' ? <SortAsc size={14}/> : <SortDesc size={14}/>) : <ArrowUpDown size={14} className="opacity-0 group-hover:opacity-100"/>}
                </div>
              </th>
              <th className="px-10 py-10 cursor-pointer group" onClick={() => handleSort('market')}>
                <div className="flex items-center gap-2">
                  Unit & Market
                  {sortConfig.key === 'market' ? (sortConfig.direction === 'asc' ? <SortAsc size={14}/> : <SortDesc size={14}/>) : <ArrowUpDown size={14} className="opacity-0 group-hover:opacity-100"/>}
                </div>
              </th>
              <th className="px-10 py-10">Status</th>
              <th className="px-10 py-10 text-right">Node Protocol</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredVendors.map(vendor => {
              const isSelected = selectedIds.has(vendor.id);
              return (
                <tr 
                  key={vendor.id} 
                  className={`hover:bg-indigo-50/40 transition-all group cursor-pointer border-l-4 ${isSelected ? 'bg-indigo-50/60 border-l-indigo-600' : 'border-l-transparent'}`} 
                  onClick={() => setSelectedVendor(vendor)}
                >
                  <td className="px-10 py-8" onClick={(e) => toggleSelect(vendor.id, e)}>
                    <button className={`transition-colors ${isSelected ? 'text-indigo-600' : 'text-slate-200 group-hover:text-indigo-300'}`}>
                       {isSelected ? <CheckSquare size={24}/> : <Square size={24}/>}
                    </button>
                  </td>
                  <td className="px-10 py-8">
                    <div className="font-black text-slate-950 uppercase tracking-tight text-base leading-none group-hover:text-indigo-600 transition-colors">{vendor.name}</div>
                    <div className="text-[10px] text-slate-400 font-bold mt-2 tracking-widest uppercase">ID: {vendor.id}</div>
                  </td>
                  <td className="px-10 py-8">
                      <div className="font-mono text-xs font-black text-slate-800 tracking-[0.2em]">#{vendor.shopNumber}</div>
                      <div className="text-[10px] text-slate-400 uppercase font-black tracking-widest mt-2 flex items-center gap-1.5">
                         <MapPin size={10}/> {MARKETS.find(m => m.id === vendor.marketId)?.name}
                      </div>
                  </td>
                  <td className="px-10 py-8">
                     <span className={`px-5 py-2 rounded-full text-[9px] font-black uppercase tracking-widest border-2 transition-all ${vendor.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                        {vendor.status}
                     </span>
                  </td>
                  <td className="px-10 py-8 text-right" onClick={(e) => e.stopPropagation()}>
                      <button 
                        onClick={() => setQrModalVendor(vendor)}
                        className="flex items-center gap-3 ml-auto px-6 py-3 bg-slate-950 hover:bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg group/qr"
                      >
                        <QrCode size={16} className="group-hover/qr:scale-110 transition-transform" />
                        <span>Issue Token</span>
                      </button>
                  </td>
                </tr>
              );
            })}
            {filteredVendors.length === 0 && (
              <tr>
                <td colSpan={5} className="px-10 py-32 text-center text-slate-400 bg-slate-50/50">
                  <Store size={64} className="mx-auto mb-6 opacity-10" />
                  <p className="font-black uppercase tracking-[0.4em] text-sm text-slate-950">No Entities Triangulated</p>
                  <p className="text-xs font-bold uppercase tracking-widest mt-2">Adjust registry filters or search parameters</p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Floating Bulk Action Bar */}
      {selectedIds.size > 0 && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] w-full max-w-5xl px-4 animate-in slide-in-from-bottom-10">
           <div className="bg-slate-950 text-white rounded-[32px] p-6 shadow-[0_40px_80px_rgba(0,0,0,0.5)] border-4 border-slate-900 flex items-center justify-between gap-8">
              <div className="flex items-center gap-6 pl-4 border-l-4 border-indigo-600">
                 <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-xl">
                    {selectedIds.size}
                 </div>
                 <div>
                    <p className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-400">Entities Selected</p>
                    <p className="text-sm font-bold text-slate-400">Perform Mass Ledger Transition</p>
                 </div>
              </div>

              <div className="flex gap-2">
                 <button 
                  onClick={() => handleBulkAction('ACTIVATE')}
                  className="flex items-center gap-3 bg-emerald-600 hover:bg-emerald-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                  title="Activate"
                 >
                    <Play size={16}/> Activate
                 </button>
                 <button 
                  onClick={() => handleBulkAction('SUSPEND')}
                  className="flex items-center gap-3 bg-amber-600 hover:bg-amber-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                  title="Suspend"
                 >
                    <Ban size={16}/> Suspend
                 </button>

                 {/* New Bulk Rent Actions */}
                 <button 
                  onClick={() => handleBulkAction('SET_DUE_DATE')}
                  className="flex items-center gap-3 bg-blue-600 hover:bg-blue-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                  title="Set Due Date"
                 >
                    <CalendarCheck size={16}/> Cycle
                 </button>
                 <button 
                  onClick={() => handleBulkAction('MARK_PAID')}
                  className="flex items-center gap-3 bg-indigo-600 hover:bg-indigo-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                  title="Mark Paid"
                 >
                    <CreditCard size={16}/> Paid
                 </button>

                 {isSuperAdmin && (
                   <button 
                    onClick={() => handleBulkAction('DELETE')}
                    className="flex items-center gap-3 bg-rose-600 hover:bg-rose-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                    title="Purge"
                   >
                      <Trash2 size={16}/> Purge
                   </button>
                 )}
                 <div className="w-px bg-slate-800 h-10 mx-2 self-center"></div>
                 <button 
                  onClick={() => setSelectedIds(new Set())}
                  className="p-4 hover:bg-slate-900 text-slate-500 hover:text-white rounded-2xl transition-colors"
                 >
                    <X size={24}/>
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* QR Modal */}
      {qrModalVendor && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-2xl z-[200] flex items-center justify-center p-4 animate-in fade-in">
           <div className="bg-white rounded-[72px] shadow-2xl max-w-md w-full p-16 text-center relative overflow-hidden group">
              <div className="absolute top-0 left-0 w-full h-3 bg-indigo-600"></div>
              <button onClick={() => setQrModalVendor(null)} className="absolute top-10 right-10 text-slate-300 hover:text-slate-950 transition-all hover:rotate-90 duration-500"><X size={44}/></button>

              <div className="mb-12">
                <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 shadow-2xl ring-8 ring-white">
                  <ShieldCheck size={48} />
                </div>
                <h3 className="text-3xl font-black text-slate-900 tracking-tighter uppercase leading-none mb-3">Operator Token</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-[0.2em]">{qrModalVendor.name}</p>
              </div>

              <div className="bg-slate-950 p-12 rounded-[56px] shadow-2xl mb-12 border-4 border-slate-900 flex flex-col items-center justify-center">
                 <div className="bg-white p-6 rounded-[40px] shadow-inner relative z-10">
                    <QrCode size={180} className="text-slate-900" />
                 </div>
                 <p className="text-indigo-400 mt-10 font-mono font-black tracking-[0.4em] text-sm uppercase">KEY-{qrModalVendor.id.toUpperCase()}</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <Button variant="secondary" className="h-16 rounded-3xl font-black uppercase text-[10px] tracking-widest border-4 border-slate-50 hover:bg-slate-50 transition-all"><Printer size={18} className="mr-3"/> Print</Button>
                 <Button className="h-16 rounded-3xl font-black uppercase text-[10px] tracking-widest shadow-xl bg-indigo-600 border-none transition-all active:scale-95"><Download size={18} className="mr-3"/> Export</Button>
              </div>
           </div>
        </div>
      )}

      {selectedVendor && (
        <VendorDetailsModal 
          vendor={selectedVendor} 
          userRole={userRole} 
          onClose={() => setSelectedVendor(null)} 
          onUpdateVendor={(u) => setVendors(prev => prev.map(v => v.id === u.id ? u : v))} 
        />
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Vendor, UserRole, ProductCategory } from '../types';
import { MOCK_VENDORS, MARKETS } from '../constants';
import { 
  Search, QrCode, UserPlus, Store, ArrowUpDown, 
  ShieldCheck, Play, Ban, X, Download, Printer, Filter, 
  CheckSquare, Square, DollarSign, ListFilter, MoreVertical,
  Building2, MapPin, User, ChevronDown, ExternalLink, Trash2,
  AlertCircle, CheckCircle2, FileJson, CalendarCheck, CreditCard,
  SortAsc, SortDesc
} from 'lucide-react';
import { Button } from './ui/Button';
import { VendorDetailsModal } from './VendorDetailsModal';

interface VendorModuleProps {
  userRole?: UserRole;
  currentUserId?: string;
  marketId?: string;
}

type SortConfig = {
  key: 'market' | 'name' | 'rent' | null;
  direction: 'asc' | 'desc';
};

export const VendorModule: React.FC<VendorModuleProps> = ({ 
  userRole = UserRole.USER, 
  currentUserId, 
  marketId 
}) => {
  const [vendors, setVendors] = useState<Vendor[]>(MOCK_VENDORS);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: null, direction: 'asc' });

  const isSuperAdmin = userRole === UserRole.SUPER_ADMIN;
  const isMarketAdmin = userRole === UserRole.MARKET_ADMIN;
  const isAdmin = isSuperAdmin || isMarketAdmin;

  const initialMarket = isMarketAdmin ? marketId : 'ALL';
  const [selectedMarket, setSelectedMarket] = useState(initialMarket || 'ALL');
  const [statusFilter, setStatusFilter] = useState('ALL');

  const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(null);
  const [qrModalVendor, setQrModalVendor] = useState<Vendor | null>(null);

  // Computed: Filtered and Sorted list for display and bulk logic
  const filteredVendors = useMemo(() => {
    let result = vendors.filter(v => {
      const term = searchTerm.toLowerCase();
      const matchesSearch = v.name.toLowerCase().includes(term) || v.shopNumber.toLowerCase().includes(term);
      const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;

      let matchesMarket = true;
      if (isMarketAdmin) {
        matchesMarket = v.marketId === marketId;
      } else {
        matchesMarket = selectedMarket === 'ALL' || v.marketId === selectedMarket;
      }

      return matchesSearch && matchesStatus && matchesMarket;
    });

    // Enhanced Relational Sorting Logic
    if (sortConfig.key) {
      result.sort((a, b) => {
        let valA: any;
        let valB: any;

        if (sortConfig.key === 'market') {
          valA = MARKETS.find(m => m.id === a.marketId)?.name || '';
          valB = MARKETS.find(m => m.id === b.marketId)?.name || '';
        } else if (sortConfig.key === 'rent') {
          valA = a.rentDue;
          valB = b.rentDue;
        } else {
          valA = a.name;
          valB = b.name;
        }

        if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }

    return result;
  }, [vendors, searchTerm, statusFilter, selectedMarket, isMarketAdmin, marketId, sortConfig]);

  const handleSort = (key: SortConfig['key']) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const exportToCSV = () => {
    const headers = ['Identity Node ID', 'Entity Name', 'Unit Number', 'Assigned Hub', 'Operational Status', 'Fiscal Liability (UGX)', 'Due Date'];
    const rows = filteredVendors.map(v => [
      v.id,
      v.name,
      v.shopNumber,
      MARKETS.find(m => m.id === v.marketId)?.name || 'Unknown',
      v.status,
      v.rentDue,
      v.rentDueDate || 'N/A'
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `mmis_vendor_manifest_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Selection Logic
  const isAllSelected = useMemo(() => {
    return filteredVendors.length > 0 && filteredVendors.every(v => selectedIds.has(v.id));
  }, [filteredVendors, selectedIds]);

  const toggleSelectAll = () => {
    const next = new Set(selectedIds);
    if (isAllSelected) {
      filteredVendors.forEach(v => next.delete(v.id));
    } else {
      filteredVendors.forEach(v => next.add(v.id));
    }
    setSelectedIds(next);
  };

  const toggleSelect = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const handleBulkAction = (action: 'ACTIVATE' | 'SUSPEND' | 'DELETE' | 'MARK_PAID' | 'SET_DUE_DATE') => {
    if (selectedIds.size === 0) return;

    if (action === 'DELETE') {
      if (!isSuperAdmin) {
        alert("RBAC SECURITY: Mass Registry Nullification is exclusive to Super Admin level.");
        return;
      }
      if (!confirm(`CAUTION: Permanently purge ${selectedIds.size} entities from the registry? This action is irreversible.`)) return;
      setVendors(prev => prev.filter(v => !selectedIds.has(v.id)));
    } else if (action === 'MARK_PAID') {
      if (!confirm(`Confirm: Mark rent as PAID for ${selectedIds.size} selected vendors?`)) return;
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, rentDue: 0 } : v));
    } else if (action === 'SET_DUE_DATE') {
      const date = prompt('Input Global Rent Due Date (YYYY-MM-DD):', new Date().toISOString().split('T')[0]);
      if (!date) return;
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, rentDueDate: date } : v));
    } else {
      const nextStatus = action === 'ACTIVATE' ? 'ACTIVE' : 'SUSPENDED';
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, status: nextStatus as any } : v));
    }

    setSelectedIds(new Set());
  };

  return (
    <div className="space-y-8 animate-in fade-in pb-32">
      {/* Module Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pb-6 border-b border-slate-200">
        <div className="flex items-center gap-6">
           <div className="w-20 h-20 bg-slate-950 text-white rounded-[32px] flex items-center justify-center shadow-2xl ring-4 ring-indigo-50">
             <Store size={36} className="text-indigo-400" />
           </div>
           <div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase leading-none">Vendor Registry</h2>
              <div className="flex items-center gap-3 mt-3">
                 <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-indigo-100 flex items-center gap-2">
                    <ShieldCheck size={12}/> {isSuperAdmin ? 'Global Treasury' : `Hub Terminal: ${marketId}`}
                 </span>
                 <p className="text-slate-400 font-bold text-sm tracking-tight uppercase tracking-widest">Node Operations Matrix</p>
              </div>
           </div>
        </div>

        <div className="flex items-center gap-3">
          <Button 
            variant="outline" 
            onClick={exportToCSV}
            className="h-14 px-8 border-2 font-black uppercase text-[11px] tracking-widest rounded-2xl bg-white transition-all hover:bg-slate-50 flex items-center gap-3 shadow-sm"
          >
            <Download size={18} className="text-indigo-600"/> Export manifest (CSV)
          </Button>
          {isAdmin && (
            <Button className="h-14 px-10 font-black uppercase text-[11px] tracking-[0.2em] bg-indigo-600 hover:bg-indigo-700 shadow-2xl rounded-2xl transition-all active:scale-95">
              <UserPlus size={20} className="mr-3"/> Enroll Entity
            </Button>
          )}
        </div>
      </div>

      {/* Control Surface */}
      <div className="bg-white p-8 rounded-[48px] border border-slate-200 shadow-xl space-y-8">
        <div className="flex flex-wrap gap-6 items-end">
          <div className="relative flex-1 min-w-[320px]">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={24} />
            <input 
              type="text" 
              placeholder="Query node identity, unit, or UID..." 
              className="w-full pl-16 pr-8 py-5 rounded-[28px] border-4 border-slate-50 bg-slate-50 font-bold text-sm text-slate-950 focus:bg-white focus:border-indigo-600 outline-none transition-all shadow-inner"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Market Scope</label>
                <div className="relative">
                  <select 
                    disabled={isMarketAdmin}
                    className={`px-6 py-4 border-2 border-slate-100 rounded-[22px] text-[10px] font-black uppercase tracking-widest bg-slate-50 outline-none appearance-none transition-all min-w-[200px] cursor-pointer ${isMarketAdmin ? 'opacity-50 grayscale' : 'hover:border-indigo-600'}`}
                    value={selectedMarket} 
                    onChange={(e) => setSelectedMarket(e.target.value)}
                  >
                      {isSuperAdmin && <option value="ALL">Global Registry</option>}
                      {MARKETS.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                  <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                </div>
              </div>
          </div>
        </div>
      </div>

      {/* Registry Matrix */}
      <div className="bg-white rounded-[64px] border border-slate-200 shadow-2xl overflow-hidden relative">
        <table className="w-full text-sm text-left">
          <thead className="bg-slate-950 text-indigo-400 font-black uppercase text-[11px] tracking-[0.4em] border-b border-slate-900">
            <tr>
              <th className="px-10 py-10 w-10">
                <button 
                  onClick={toggleSelectAll}
                  className={`transition-all ${isAllSelected ? 'text-white' : 'text-indigo-400 hover:text-white'}`}
                >
                  {isAllSelected ? <CheckSquare size={24}/> : <Square size={24}/>}
                </button>
              </th>
              <th className="px-10 py-10 cursor-pointer group select-none" onClick={() => handleSort('name')}>
                <div className="flex items-center gap-2">
                  Registry Node
                  <span className="transition-opacity group-hover:opacity-100 opacity-40">
                    {sortConfig.key === 'name' ? (sortConfig.direction === 'asc' ? <SortAsc size={14} className="text-white"/> : <SortDesc size={14} className="text-white"/>) : <ArrowUpDown size={14}/>}
                  </span>
                </div>
              </th>
              <th className="px-10 py-10 cursor-pointer group select-none" onClick={() => handleSort('market')}>
                <div className="flex items-center gap-2">
                  Unit & Hub
                  <span className="transition-opacity group-hover:opacity-100 opacity-40">
                    {sortConfig.key === 'market' ? (sortConfig.direction === 'asc' ? <SortAsc size={14} className="text-white"/> : <SortDesc size={14} className="text-white"/>) : <ArrowUpDown size={14}/>}
                  </span>
                </div>
              </th>
              <th className="px-10 py-10">Status</th>
              <th className="px-10 py-10 text-right">Node Protocol</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredVendors.map(vendor => {
              const isSelected = selectedIds.has(vendor.id);
              return (
                <tr 
                  key={vendor.id} 
                  className={`hover:bg-indigo-50/40 transition-all group cursor-pointer border-l-4 ${isSelected ? 'bg-indigo-50/60 border-l-indigo-600' : 'border-l-transparent'}`} 
                  onClick={() => setSelectedVendor(vendor)}
                >
                  <td className="px-10 py-8" onClick={(e) => toggleSelect(vendor.id, e)}>
                    <button className={`transition-colors ${isSelected ? 'text-indigo-600' : 'text-slate-200 group-hover:text-indigo-300'}`}>
                       {isSelected ? <CheckSquare size={24}/> : <Square size={24}/>}
                    </button>
                  </td>
                  <td className="px-10 py-8">
                    <div className="font-black text-slate-950 uppercase tracking-tight text-base leading-none group-hover:text-indigo-600 transition-colors">{vendor.name}</div>
                    <div className="text-[10px] text-slate-400 font-bold mt-2 tracking-widest uppercase">ID: {vendor.id}</div>
                  </td>
                  <td className="px-10 py-8">
                      <div className="font-mono text-xs font-black text-slate-800 tracking-[0.2em]">#{vendor.shopNumber}</div>
                      <div className="text-[10px] text-slate-400 uppercase font-black tracking-widest mt-2 flex items-center gap-1.5">
                         <MapPin size={10}/> {MARKETS.find(m => m.id === vendor.marketId)?.name}
                      </div>
                  </td>
                  <td className="px-10 py-8">
                     <span className={`px-5 py-2 rounded-full text-[9px] font-black uppercase tracking-widest border-2 transition-all ${vendor.status === 'ACTIVE' ? 'bg-emerald-50 text-emerald-700 border-emerald-100' : 'bg-rose-50 text-rose-700 border-rose-100'}`}>
                        {vendor.status}
                     </span>
                  </td>
                  <td className="px-10 py-8 text-right" onClick={(e) => e.stopPropagation()}>
                      <button 
                        onClick={() => setQrModalVendor(vendor)}
                        className="flex items-center gap-3 ml-auto px-6 py-3 bg-slate-950 hover:bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg group/qr"
                      >
                        <QrCode size={16} className="group-hover/qr:scale-110 transition-transform" />
                        <span>Issue Token</span>
                      </button>
                  </td>
                </tr>
              );
            })}
            {filteredVendors.length === 0 && (
              <tr>
                <td colSpan={5} className="px-10 py-32 text-center text-slate-400 bg-slate-50/50">
                  <Store size={64} className="mx-auto mb-6 opacity-10" />
                  <p className="font-black uppercase tracking-[0.4em] text-sm text-slate-950">No Entities Triangulated</p>
                  <p className="text-xs font-bold uppercase tracking-widest mt-2">Adjust registry filters or search parameters</p>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Floating Bulk Action Bar */}
      {selectedIds.size > 0 && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] w-full max-w-4xl px-4 animate-in slide-in-from-bottom-10">
           <div className="bg-slate-950 text-white rounded-[32px] p-6 shadow-[0_40px_80px_rgba(0,0,0,0.5)] border-4 border-slate-900 flex items-center justify-between gap-8">
              <div className="flex items-center gap-6 pl-4 border-l-4 border-indigo-600">
                 <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center font-black text-xl">
                    {selectedIds.size}
                 </div>
                 <div>
                    <p className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-400">Entities Selected</p>
                    <p className="text-sm font-bold text-slate-400">Perform Mass Ledger Transition</p>
                 </div>
              </div>

              <div className="flex gap-2">
                 <button 
                  onClick={() => handleBulkAction('ACTIVATE')}
                  className="flex items-center gap-3 bg-emerald-600 hover:bg-emerald-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                  title="Activate All"
                 >
                    <Play size={16}/> Activate
                 </button>
                 <button 
                  onClick={() => handleBulkAction('SUSPEND')}
                  className="flex items-center gap-3 bg-amber-600 hover:bg-amber-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                  title="Suspend All"
                 >
                    <Ban size={16}/> Suspend
                 </button>

                 <button 
                  onClick={() => handleBulkAction('SET_DUE_DATE')}
                  className="flex items-center gap-3 bg-blue-600 hover:bg-blue-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                  title="Set Rent Cycle"
                 >
                    <CalendarCheck size={16}/> Cycle
                 </button>
                 <button 
                  onClick={() => handleBulkAction('MARK_PAID')}
                  className="flex items-center gap-3 bg-indigo-600 hover:bg-indigo-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                  title="Bulk Payment Sync"
                 >
                    <CreditCard size={16}/> Paid
                 </button>

                 {isSuperAdmin && (
                   <button 
                    onClick={() => handleBulkAction('DELETE')}
                    className="flex items-center gap-3 bg-rose-600 hover:bg-rose-700 px-6 h-14 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                    title="Purge Selection"
                   >
                      <Trash2 size={16}/> Purge
                   </button>
                 )}
                 <div className="w-px bg-slate-800 h-10 mx-2 self-center"></div>
                 <button 
                  onClick={() => setSelectedIds(new Set())}
                  className="p-4 hover:bg-slate-900 text-slate-500 hover:text-white rounded-2xl transition-colors"
                 >
                    <X size={24}/>
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* QR Modal (Unchanged) */}
      {qrModalVendor && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-2xl z-[200] flex items-center justify-center p-4 animate-in fade-in">
           <div className="bg-white rounded-[72px] shadow-2xl max-w-md w-full p-16 text-center relative overflow-hidden group">
              <div className="absolute top-0 left-0 w-full h-3 bg-indigo-600"></div>
              <button onClick={() => setQrModalVendor(null)} className="absolute top-10 right-10 text-slate-300 hover:text-slate-950 transition-all hover:rotate-90 duration-500"><X size={44}/></button>

              <div className="mb-12">
                <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-[32px] flex items-center justify-center mx-auto mb-8 shadow-2xl ring-8 ring-white">
                  <ShieldCheck size={48} />
                </div>
                <h3 className="text-3xl font-black text-slate-900 tracking-tighter uppercase leading-none mb-3">Operator Token</h3>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-[0.2em]">{qrModalVendor.name}</p>
              </div>

              <div className="bg-slate-950 p-12 rounded-[56px] shadow-2xl mb-12 border-4 border-slate-900 flex flex-col items-center justify-center">
                 <div className="bg-white p-6 rounded-[40px] shadow-inner relative z-10">
                    <QrCode size={180} className="text-slate-900" />
                 </div>
                 <p className="text-indigo-400 mt-10 font-mono font-black tracking-[0.4em] text-sm uppercase">KEY-{qrModalVendor.id.toUpperCase()}</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                 <Button variant="secondary" className="h-16 rounded-3xl font-black uppercase text-[10px] tracking-widest border-4 border-slate-50 hover:bg-slate-50 transition-all"><Printer size={18} className="mr-3"/> Print</Button>
                 <Button className="h-16 rounded-3xl font-black uppercase text-[10px] tracking-widest shadow-xl bg-indigo-600 border-none transition-all active:scale-95"><Download size={18} className="mr-3"/> Export</Button>
              </div>
           </div>
        </div>
      )}

      {selectedVendor && (
        <VendorDetailsModal 
          vendor={selectedVendor} 
          userRole={userRole} 
          onClose={() => setSelectedVendor(null)} 
          onUpdateVendor={(u) => setVendors(prev => prev.map(v => v.id === u.id ? u : v))} 
        />
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Vendor, UserRole, ProductCategory } from '../types';
import { MOCK_VENDORS, MARKETS } from '../constants';
import { 
  Search, QrCode, UserPlus, Store, ArrowUpDown, 
  ShieldCheck, Play, Ban, X, Download, Printer, Filter, 
  CheckSquare, Square, DollarSign, ListFilter, MoreVertical,
  Building2, MapPin, User, ChevronDown, ExternalLink, Trash2,
  AlertCircle, CheckCircle2, FileJson, CalendarCheck, CreditCard,
  SortAsc, SortDesc
} from 'lucide-react';
import { Button } from './ui/Button';
import { VendorDetailsModal } from './VendorDetailsModal';

interface VendorModuleProps {
  userRole?: UserRole;
  currentUserId?: string;
  marketId?: string;
}

type SortConfig = {
  key: 'market' | 'name' | 'rent' | null;
  direction: 'asc' | 'desc';
};

export const VendorModule: React.FC<VendorModuleProps> = ({ 
  userRole = UserRole.USER, 
  currentUserId, 
  marketId 
}) => {
  const [vendors, setVendors] = useState<Vendor[]>(MOCK_VENDORS);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<SortConfig>({ key: 'name', direction: 'asc' });

  const isSuperAdmin = userRole === UserRole.SUPER_ADMIN;
  const isMarketAdmin = userRole === UserRole.MARKET_ADMIN;
  const isAdmin = isSuperAdmin || isMarketAdmin;

  // Market filtering logic
  const initialMarket = isMarketAdmin ? marketId : 'ALL';
  const [selectedMarket, setSelectedMarket] = useState(initialMarket || 'ALL');
  const [statusFilter, setStatusFilter] = useState('ALL');

  const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(null);
  const [qrModalVendor, setQrModalVendor] = useState<Vendor | null>(null);

  // Computed: Filtered and Sorted list for display and bulk logic
  const filteredVendors = useMemo(() => {
    let result = vendors.filter(v => {
      const term = searchTerm.toLowerCase();
      const matchesSearch = v.name.toLowerCase().includes(term) || v.shopNumber.toLowerCase().includes(term);
      const matchesStatus = statusFilter === 'ALL' || v.status === statusFilter;

      let matchesMarket = true;
      if (isMarketAdmin) {
        matchesMarket = v.marketId === marketId;
      } else {
        matchesMarket = selectedMarket === 'ALL' || v.marketId === selectedMarket;
      }

      return matchesSearch && matchesStatus && matchesMarket;
    });

    // Enhanced Relational Sorting Logic
    if (sortConfig.key) {
      result.sort((a, b) => {
        let valA: any;
        let valB: any;

        if (sortConfig.key === 'market') {
          // Sort by Market NAME instead of ID for better UX
          valA = MARKETS.find(m => m.id === a.marketId)?.name || '';
          valB = MARKETS.find(m => m.id === b.marketId)?.name || '';
        } else if (sortConfig.key === 'rent') {
          valA = a.rentDue;
          valB = b.rentDue;
        } else {
          valA = a.name;
          valB = b.name;
        }

        if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
        if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }

    return result;
  }, [vendors, searchTerm, statusFilter, selectedMarket, isMarketAdmin, marketId, sortConfig]);

  const handleSort = (key: SortConfig['key']) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const exportToCSV = () => {
    // Column Headers
    const headers = [
      'Registry ID', 
      'Vendor Name', 
      'Shop Number', 
      'Market Hub', 
      'Category',
      'Operational Status', 
      'Current Rent Arrears (UGX)', 
      'Due Date',
      'Contact Email',
      'Phone Number'
    ];

    // Map through the CURRENTLY FILTERED list
    const rows = filteredVendors.map(v => [
      v.id,
      `"${v.name}"`, // Quote strings to prevent issues with commas in names
      v.shopNumber,
      `"${MARKETS.find(m => m.id === v.marketId)?.name || 'Unknown'}"`,
      v.storeType || 'N/A',
      v.status,
      v.rentDue,
      v.rentDueDate || 'N/A',
      v.email || 'N/A',
      v.phone || 'N/A'
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.join(','))
    ].join('\n');

    // Create and download the blob
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `mmis_vendor_registry_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Selection Logic
  const isAllSelected = useMemo(() => {
    return filteredVendors.length > 0 && filteredVendors.every(v => selectedIds.has(v.id));
  }, [filteredVendors, selectedIds]);

  const toggleSelectAll = () => {
    const next = new Set(selectedIds);
    if (isAllSelected) {
      filteredVendors.forEach(v => next.delete(v.id));
    } else {
      filteredVendors.forEach(v => next.add(v.id));
    }
    setSelectedIds(next);
  };

  const toggleSelect = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const next = new Set(selectedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedIds(next);
  };

  const handleBulkAction = (action: 'ACTIVATE' | 'SUSPEND' | 'DELETE' | 'MARK_PAID' | 'SET_DUE_DATE') => {
    if (selectedIds.size === 0) return;

    if (action === 'DELETE') {
      if (!isSuperAdmin) {
        alert("RBAC SECURITY: Mass Registry Nullification is exclusive to Super Admin level.");
        return;
      }
      if (!confirm(`CAUTION: Permanently purge ${selectedIds.size} entities from the registry? This action is irreversible.`)) return;
      setVendors(prev => prev.filter(v => !selectedIds.has(v.id)));
    } else if (action === 'MARK_PAID') {
      if (!confirm(`Confirm: Mark rent as PAID for ${selectedIds.size} selected vendors?`)) return;
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, rentDue: 0 } : v));
    } else if (action === 'SET_DUE_DATE') {
      const date = prompt('Input Global Rent Due Date (YYYY-MM-DD):', new Date().toISOString().split('T')[0]);
      if (!date) return;
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, rentDueDate: date } : v));
    } else {
      const nextStatus = action === 'ACTIVATE' ? 'ACTIVE' : 'SUSPENDED';
      setVendors(prev => prev.map(v => selectedIds.has(v.id) ? { ...v, status: nextStatus as any } : v));
    }

    setSelectedIds(new Set());
  };

  return (
    <div className="space-y-8 animate-in fade-in pb-32">
      {/* Module Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pb-6 border-b border-slate-200">
        <div className="flex items-center gap-6">
           <div className="w-20 h-20 bg-slate-950 text-white rounded-[32px] flex items-center justify-center shadow-2xl ring-4 ring-indigo-50">
             <Store size={36} className="text-indigo-400" />
           </div>
           <div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase leading-none">Vendor Registry</h2>
              <div className="flex items-center gap-3 mt-3">
                 <span className="px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-[10px] font-black uppercase tracking-widest border border-indigo-100 flex items-center gap-2">
                    <ShieldCheck size={12}/> {isSuperAdmin ? 'Global Treasury' : `Hub Terminal: ${marketId}`}
                 </span>
                 <p className="text-slate-400 font-bold text-sm tracking-tight uppercase tracking-widest">Node Operations Matrix</p>
              </div>
           </div>
        </div>

        <div className="flex items-center gap-3">
          <Button 
            variant="outline" 
            onClick={exportToCSV}
            className="h-14 px-8 border-2 font-black uppercase text-[11px] tracking-widest rounded-2xl bg-white transition-all hover:bg-slate-50 flex items-center gap-3 shadow-sm group"
          >
            <Download size={18} className="text-indigo-600 group-hover:scale-110 transition-transform"/> Export manifest (CSV)
          </Button>
          {isAdmin && (
            <Button className="h-14 px-10 font-black uppercase text-[11px] tracking-[0.2em] bg-indigo-600 hover:bg-indigo-700 shadow-2xl rounded-2xl transition-all active:scale-95">
              <UserPlus size={20} className="mr-3"/> Enroll Entity
            </Button>
          )}
        </div>
      </div>

      {/* Control Surface */}
      <div className="bg-white p-8 rounded-[48px] border border-slate-200 shadow-xl space-y-8">
        <div className="flex flex-wrap gap-6 items-end">
