                 <p className="text-indigo-400 mt-10 font-mono font-black tracking-[0.4em] text-sm uppercase">
                    {qrType === 'OPERATOR' ? `KEY-${qrModalVendor.id.toUpperCase()}` : `STORE-${qrModalVendor.shopNumber}`}
